  "version": "1.0.0",
  "description": "ClerkOS Azure Durable Functions — bundle generation orchestration",
  "main": "dist/src/index.js",
  "scripts": {
    "build": "tsc",
    "watch": "tsc -w",
    "start": "func start"
  },
  "dependencies": {
    "@azure/functions": "^4.5.0",
    "durable-functions": "^3.3.1",
    "@azure/storage-blob": "^12.31.0",
    "postgres": "^3.4.3",
    "drizzle-orm": "^0.29.3"
  },
  "devDependencies": {
    "@types/node": "^20.0.0",
    "typescript": "^5.2.2",
    "azure-functions-core-tools": "^4"
  }
}

import * as df from 'durable-functions';
import { app, InvocationContext } from '@azure/functions';

// ─── Types ────────────────────────────────────────────────────────────────────

type BundleInput = {
  bundleId: number;
  orchestrationId: string;
  tenantId: string;
  caseId: number;
};

type ValidationResult = {
  valid: boolean;
  bundleId: number;
  tenantId: string;
  caseId: number;
  documents: Array<{ id: number; fileName: string; blobPath: string | null }>;
  reason?: string;
};

type RenderResult = {
  pageCount: number;
  pdfBuffer: Buffer;
};

// ─── Orchestrator ─────────────────────────────────────────────────────────────

const bundleOrchestrator = df.orchestrator(function* (context: df.OrchestrationContext) {
  const input: BundleInput = context.df.getInput();

  // 1. Validate bundle eligibility
  const validation: ValidationResult = yield context.df.callActivity(
    'validateBundle',
    input,
  );

  if (!validation.valid) {
    yield context.df.callActivity('failBundle', {
      bundleId: input.bundleId,
      tenantId: input.tenantId,
      reason: validation.reason,
    });
    return { status: 'failed', reason: validation.reason };
  }

  // 2. Render pages in parallel (one activity per document)
  const renderTasks = validation.documents.map((doc) =>
    context.df.callActivity('renderDocumentPage', {
      ...doc,
      tenantId: input.tenantId,
    }),
  );
  const pages: RenderResult[] = yield context.df.Task.all(renderTasks);

  // 3. Merge pages into a single PDF bundle
  const pdfBlobPath: string = yield context.df.callActivity('mergeBundlePDF', {
    bundleId: input.bundleId,
    tenantId: input.tenantId,
    caseId: input.caseId,
    pages,
    documents: validation.documents,
  });

  // 4. Finalize: write blob path, audit hash, mark ready
  yield context.df.callActivity('finalizeBundle', {
    bundleId: input.bundleId,
    tenantId: input.tenantId,
    caseId: input.caseId,
    pdfBlobPath,
    orchestrationId: input.orchestrationId,
  });

  return { status: 'ready', pdfBlobPath };
});

df.app.orchestration('bundleOrchestrator', bundleOrchestrator);

// ─── Activity: validateBundle ─────────────────────────────────────────────────

df.app.activity('validateBundle', {
  handler: async (input: BundleInput): Promise<ValidationResult> => {
    // Query the database for case documents approved for bundle
    // (Omitted: wire up DB connection as in server/trpc/db.ts)
    const documents: Array<{ id: number; fileName: string; blobPath: string | null }> = [];

    if (documents.length === 0) {
      return {
        valid: false,
        bundleId: input.bundleId,
        tenantId: input.tenantId,
        caseId: input.caseId,
        documents: [],
        reason: 'No documents approved for bundle',
      };
    }

    return {
      valid: true,
      bundleId: input.bundleId,
      tenantId: input.tenantId,
      caseId: input.caseId,
      documents,
    };
  },
});

// ─── Activity: renderDocumentPage ────────────────────────────────────────────

df.app.activity('renderDocumentPage', {
  handler: async (input: {
    id: number;
    fileName: string;
    blobPath: string | null;
    tenantId: string;
  }): Promise<RenderResult> => {
    // Download blob → render page(s) → return buffer
    // Implementation: use @azure/storage-blob to download, pdflib to process
    return { pageCount: 1, pdfBuffer: Buffer.alloc(0) };
  },
});

// ─── Activity: mergeBundlePDF ─────────────────────────────────────────────────

df.app.activity('mergeBundlePDF', {
  handler: async (input: {
    bundleId: number;
    tenantId: string;
    caseId: number;
    pages: RenderResult[];
    documents: Array<{ id: number; fileName: string }>;
  }): Promise<string> => {
    // Merge all page buffers with pdflib
    // Upload merged PDF to Azure Blob Storage
    // Return blob path
    const blobPath = `tenants/${input.tenantId}/bundles/${input.bundleId}/bundle.pdf`;
    return blobPath;
  },
});

// ─── Activity: finalizeBundle ─────────────────────────────────────────────────

df.app.activity('finalizeBundle', {
  handler: async (input: {
    bundleId: number;
    tenantId: string;
    caseId: number;
    pdfBlobPath: string;
    orchestrationId: string;
  }): Promise<void> => {
    // Update bundle record in DB: status = 'ready', pdfBlobPath, auditHash
    // Write audit event
    console.log(`[FinalizeBundle] Bundle ${input.bundleId} ready at ${input.pdfBlobPath}`);
  },
});

// ─── Activity: failBundle ─────────────────────────────────────────────────────

df.app.activity('failBundle', {
  handler: async (input: { bundleId: number; tenantId: string; reason?: string }): Promise<void> => {
    // Update bundle record: status = 'failed'
    console.error(`[FailBundle] Bundle ${input.bundleId} failed: ${input.reason}`);
  },
});

// ─── Service Bus trigger: start orchestration ─────────────────────────────────

app.serviceBusTrigger('startBundleOrchestration', {
  queueName: 'clerkos-bundles',
  connection: 'AzureWebJobsServiceBus',
  handler: async (message: BundleInput, context: InvocationContext): Promise<void> => {
    const client = df.getClient(context);
    await client.startNew('bundleOrchestrator', {
      instanceId: message.orchestrationId,
      input: message,
    });
    context.log(`[StartOrchestration] Instance ${message.orchestrationId} started`);
  },
});

// =============================================================================
// ClerkOS v1.1 — Main Bicep Infrastructure Template
// Deploys all Azure resources for a complete ClerkOS environment.
//
// Usage:
//   az group create --name rg-clerkos-<env> --location uksouth
//   az deployment group create \
//     --resource-group rg-clerkos-<env> \
//     --template-file deploy/main.bicep \
//     --parameters @deploy/parameters.<env>.json
// =============================================================================

@description('Deployment environment')
@allowed(['dev', 'staging', 'prod'])
param environment string

@description('Short application name used in resource naming')
param appName string = 'clerkos'

@description('Azure region')
param location string = resourceGroup().location

@description('PostgreSQL administrator password')
@secure()
param dbAdminPassword string

@description('Azure AD B2C Tenant Name (e.g. contoso)')
param b2cTenantName string

@description('Azure AD B2C Application Client ID')
param b2cClientId string

@description('Initial tenant slug for bootstrapping')
param initialTenantSlug string = 'default'

// =============================================================================
// Naming — {appName}-{environment}-{resource}
// =============================================================================

var prefix = '${appName}-${environment}'
var pgServerName       = '${prefix}-pg'
var pgDbName           = '${prefix}-db'
var storageAccountName = replace('${appName}${environment}docs', '-', '')
var serviceBusNsName   = '${prefix}-sb'
var acrName            = replace('${appName}${environment}cr', '-', '')
var containerAppEnvName = '${prefix}-cae'
var containerAppName   = '${prefix}-api'
var staticWebAppName   = '${prefix}-web'
var keyVaultName       = '${prefix}-kv'
var logAnalyticsName   = '${prefix}-log'
var appInsightsName    = '${prefix}-ai'
var dbAdminLogin       = '${appName}admin'

// =============================================================================
// Log Analytics
// =============================================================================

var resourceTags = {
  environment: environment
  application: 'vaultline-brand-suite'
}

resource logAnalytics 'Microsoft.OperationalInsights/workspaces@2022-10-01' = {
  name: logAnalyticsName
  location: location
  tags: resourceTags
  properties: {
    sku: { name: 'PerGB2018' }
    retentionInDays: environment == 'prod' ? 90 : 30
  }
}

// =============================================================================
// Application Insights
// =============================================================================

resource appInsights 'Microsoft.Insights/components@2020-02-02' = {
  name: appInsightsName
  location: location
  kind: 'web'
  tags: resourceTags
  properties: {
    Application_Type: 'web'
    WorkspaceResourceId: logAnalytics.id
    publicNetworkAccessForIngestion: 'Enabled'
    publicNetworkAccessForQuery: 'Enabled'
  }
}

// =============================================================================
// Key Vault
// =============================================================================

resource keyVault 'Microsoft.KeyVault/vaults@2023-07-01' = {
  name: keyVaultName
  location: location
  tags: resourceTags
  properties: {
    sku: { family: 'A', name: 'standard' }
    tenantId: subscription().tenantId
    enableRbacAuthorization: true
    enableSoftDelete: true
    softDeleteRetentionInDays: environment == 'prod' ? 90 : 7
  }
}

resource kvSecretDbPassword 'Microsoft.KeyVault/vaults/secrets@2023-07-01' = {
  parent: keyVault
  name: 'db-admin-password'
  properties: { value: dbAdminPassword }
}

resource kvSecretAppInsights 'Microsoft.KeyVault/vaults/secrets@2023-07-01' = {
  parent: keyVault
  name: 'application-insights-connection-string'
  properties: { value: appInsights.properties.ConnectionString }
}

// DATABASE_URL stored as a secret so Container App can reference it
resource kvSecretDatabaseUrl 'Microsoft.KeyVault/vaults/secrets@2023-07-01' = {
  parent: keyVault
  name: 'database-url'
  properties: {
    value: 'postgresql://${dbAdminLogin}:${dbAdminPassword}@${pgServerName}.postgres.database.azure.com/${pgDbName}?sslmode=require'
  }
}

resource sbRootRule 'Microsoft.ServiceBus/namespaces/authorizationRules@2022-10-01-preview' existing = {
  parent: serviceBusNs
  name: 'RootManageSharedAccessKey'
}

resource kvSecretServiceBus 'Microsoft.KeyVault/vaults/secrets@2023-07-01' = {
  parent: keyVault
  name: 'service-bus-connection-string'
  properties: {
    value: sbRootRule.listKeys().primaryConnectionString
  }
}

// =============================================================================
// Azure Database for PostgreSQL Flexible Server
// =============================================================================

resource pgServer 'Microsoft.DBforPostgreSQL/flexibleServers@2023-06-01-preview' = {
  name: pgServerName
  location: location
  tags: resourceTags
  sku: {
    name: environment == 'prod' ? 'Standard_D4ds_v5' : 'Standard_B2ms'
    tier: environment == 'prod' ? 'GeneralPurpose' : 'Burstable'
  }
  properties: {
    administratorLogin: dbAdminLogin
    administratorLoginPassword: dbAdminPassword
    version: '16'
    storage: {
      storageSizeGB: environment == 'prod' ? 128 : 32
    }
    backup: {
      backupRetentionDays: environment == 'prod' ? 35 : 7
      geoRedundantBackup: environment == 'prod' ? 'Enabled' : 'Disabled'
    }
    highAvailability: {
      mode: environment == 'prod' ? 'ZoneRedundant' : 'Disabled'
    }
    authConfig: {
      activeDirectoryAuth: 'Disabled'
      passwordAuth: 'Enabled'
    }
  }
}

resource pgDatabase 'Microsoft.DBforPostgreSQL/flexibleServers/databases@2023-06-01-preview' = {
  parent: pgServer
  name: pgDbName
  properties: {
    charset: 'UTF8'
    collation: 'en_US.utf8'
  }
}

// Allow Azure services to reach Postgres (dev/staging only — use VNet in prod)
resource pgFirewallAzure 'Microsoft.DBforPostgreSQL/flexibleServers/firewallRules@2023-06-01-preview' = if (environment != 'prod') {
  parent: pgServer
  name: 'AllowAzureServices'
  properties: {
    startIpAddress: '0.0.0.0'
    endIpAddress: '0.0.0.0'
  }
}

// =============================================================================
// Blob Storage (immutable legal document retention)
// =============================================================================

resource storageAccount 'Microsoft.Storage/storageAccounts@2023-01-01' = {
  name: storageAccountName
  location: location
  kind: 'StorageV2'
  tags: resourceTags
  sku: { name: environment == 'prod' ? 'Standard_GRS' : 'Standard_LRS' }
  properties: {
    minimumTlsVersion: 'TLS1_2'
    allowBlobPublicAccess: false
    supportsHttpsTrafficOnly: true
    isVersioningEnabled: true
  }
}

resource blobService 'Microsoft.Storage/storageAccounts/blobServices@2023-01-01' = {
  parent: storageAccount
  name: 'default'
  properties: {
    isVersioningEnabled: true
    deleteRetentionPolicy: {
      enabled: true
      days: environment == 'prod' ? 365 : 30
    }
  }
}

resource documentsContainer 'Microsoft.Storage/storageAccounts/blobServices/containers@2023-01-01' = {
  parent: blobService
  name: 'clerkos-documents'
  properties: {
    publicAccess: 'None'
    immutableStorageWithVersioning: environment == 'prod' ? { enabled: true } : null
  }
}

// =============================================================================
// Service Bus
// =============================================================================

resource serviceBusNs 'Microsoft.ServiceBus/namespaces@2022-10-01-preview' = {
  name: serviceBusNsName
  location: location
  tags: resourceTags
  sku: {
    name: environment == 'prod' ? 'Premium' : 'Standard'
    tier: environment == 'prod' ? 'Premium' : 'Standard'
  }
}

resource bundleQueue 'Microsoft.ServiceBus/namespaces/queues@2022-10-01-preview' = {
  parent: serviceBusNs
  name: 'clerkos-bundles'
  properties: {
    maxSizeInMegabytes: 1024
    defaultMessageTimeToLive: 'P14D'
    lockDuration: 'PT5M'
    maxDeliveryCount: 3
    deadLetteringOnMessageExpiration: true
  }
}

resource tasksQueue 'Microsoft.ServiceBus/namespaces/queues@2022-10-01-preview' = {
  parent: serviceBusNs
  name: 'clerkos-tasks'
  properties: {
    maxSizeInMegabytes: 1024
    defaultMessageTimeToLive: 'P7D'
    lockDuration: 'PT2M'
    maxDeliveryCount: 5
  }
}

// =============================================================================
// Container Registry
// =============================================================================

resource acr 'Microsoft.ContainerRegistry/registries@2023-07-01' = {
  name: acrName
  location: location
  tags: resourceTags
  sku: { name: environment == 'prod' ? 'Premium' : 'Basic' }
  properties: { adminUserEnabled: true }
}

// =============================================================================
// Container Apps (tRPC / Express API)
// =============================================================================

resource containerAppEnv 'Microsoft.App/managedEnvironments@2023-05-01' = {
  name: containerAppEnvName
  location: location
  tags: resourceTags
  properties: {
    appLogsConfiguration: {
      destination: 'log-analytics'
      logAnalyticsConfiguration: {
        customerId: logAnalytics.properties.customerId
        sharedKey: logAnalytics.listKeys().primarySharedKey
      }
    }
  }
}

resource containerApp 'Microsoft.App/containerApps@2023-05-01' = {
  name: containerAppName
  location: location
  tags: resourceTags
  identity: { type: 'SystemAssigned' }
  properties: {
    managedEnvironmentId: containerAppEnv.id
    configuration: {
      ingress: {
        external: true
        targetPort: 3000
        transport: 'http'
        corsPolicy: {
          allowedOrigins: ['*']
          allowedMethods: ['GET', 'POST', 'OPTIONS']
          allowedHeaders: ['*']
        }
      }
      registries: [
        {
          server: acr.properties.loginServer
          username: acr.listCredentials().username
          passwordSecretRef: 'acr-password'
        }
      ]
      secrets: [
        {
          name: 'acr-password'
          value: acr.listCredentials().passwords[0].value
        }
        {
          name: 'database-url'
          keyVaultUrl: '${keyVault.properties.vaultUri}secrets/database-url'
          identity: 'system'
        }
        {
          name: 'service-bus-connection'
          keyVaultUrl: '${keyVault.properties.vaultUri}secrets/service-bus-connection-string'
          identity: 'system'
        }
      ]
    }
    template: {
      scale: {
        minReplicas: environment == 'prod' ? 2 : 0
        maxReplicas: environment == 'prod' ? 10 : 3
        rules: [
          {
            name: 'http-scaling'
            http: { metadata: { concurrentRequests: '100' } }
          }
        ]
      }
      containers: [
        {
          name: 'api'
          image: '${acr.properties.loginServer}/clerkos-api:latest'
          resources: {
            cpu: json(environment == 'prod' ? '1.0' : '0.5')
            memory: environment == 'prod' ? '2Gi' : '1Gi'
          }
          env: [
            { name: 'NODE_ENV',                          value: environment == 'prod' ? 'production' : environment }
            { name: 'PORT',                              value: '3000' }
            { name: 'DATABASE_URL',                      secretRef: 'database-url' }
            { name: 'AZURE_SERVICE_BUS_CONNECTION_STRING', secretRef: 'service-bus-connection' }
            { name: 'AZURE_B2C_TENANT_NAME',             value: b2cTenantName }
            { name: 'AZURE_B2C_CLIENT_ID',               value: b2cClientId }
            { name: 'APPLICATIONINSIGHTS_CONNECTION_STRING', value: appInsights.properties.ConnectionString }
            { name: 'DEFAULT_TENANT_SLUG',               value: initialTenantSlug }
          ]
          probes: [
            {
              type: 'Liveness'
              httpGet: {
                path: '/api/ping'
                port: 3000
                scheme: 'HTTP'
              }
              initialDelaySeconds: 10
              periodSeconds: 30
              failureThreshold: 3
            }
          ]
        }
      ]
    }
  }
}

// =============================================================================
// Key Vault RBAC — grant Container App's managed identity secret read access
// Role: Key Vault Secrets User (4633458b-17de-408a-b874-0445c86b69e6)
// =============================================================================

resource kvSecretsUserRole 'Microsoft.Authorization/roleAssignments@2022-04-01' = {
  name: guid(keyVault.id, containerApp.id, '4633458b-17de-408a-b874-0445c86b69e6')
  scope: keyVault
  properties: {
    roleDefinitionId: subscriptionResourceId('Microsoft.Authorization/roleDefinitions', '4633458b-17de-408a-b874-0445c86b69e6')
    principalId: containerApp.identity.principalId
    principalType: 'ServicePrincipal'
  }
}

// =============================================================================
// Static Web App (React frontend)
// =============================================================================

resource staticWebApp 'Microsoft.Web/staticSites@2023-01-01' = {
  name: staticWebAppName
  location: location
  sku: { name: environment == 'prod' ? 'Standard' : 'Free' }
  properties: {}
}

// =============================================================================
// Outputs
// =============================================================================

output containerAppUrl        string = 'https://${containerApp.properties.configuration.ingress.fqdn}'
output staticWebAppUrl        string = 'https://${staticWebApp.properties.defaultHostname}'
output acrLoginServer         string = acr.properties.loginServer
output keyVaultUri            string = keyVault.properties.vaultUri
