import { and, eq } from 'drizzle-orm';
import { bundles, cases, documents } from '../drizzle/schema';
import type { Case } from '../drizzle/schema';
import { writeAuditEvent } from '../trpc/db';
import type { DrizzleDb } from './types';

// ─── Type aliases ─────────────────────────────────────────────────────────────

export type CaseStatus = 'open' | 'in_progress' | 'closed' | 'on_hold';

export type Result<T> =
  | { ok: true; value: T }
  | { ok: false; error: string };

// ─── State machine transition map ─────────────────────────────────────────────

const VALID_TRANSITIONS: Record<CaseStatus, CaseStatus[]> = {
  open:        ['in_progress', 'on_hold', 'closed'],
  in_progress: ['closed', 'on_hold', 'open'],
  on_hold:     ['open', 'in_progress', 'closed'],
  closed:      ['open'], // reopen
};

// ─── ClerkOS Engine ───────────────────────────────────────────────────────────

export class ClerkOSEngine {
  constructor(
    private readonly db: DrizzleDb,
    private readonly tenantId: string,
  ) {}

  // ─── Case transitions ───────────────────────────────────────────────────────

  async transitionCase(
    caseId: number,
    newStatus: CaseStatus,
    actorId: number,
    actorOpenId: string,
  ): Promise<Result<Case>> {
    // Fetch case scoped to this tenant
    const [existing] = await this.db
      .select()
      .from(cases)
      .where(and(eq(cases.id, caseId), eq(cases.tenantId, this.tenantId)))
      .limit(1);

    if (!existing) {
      return { ok: false, error: `Case ${caseId} not found` };
    }

    const currentStatus = existing.status as CaseStatus;
    const allowed = VALID_TRANSITIONS[currentStatus] ?? [];

    if (!allowed.includes(newStatus)) {
      return {
        ok: false,
        error: `Transition ${currentStatus} → ${newStatus} is not permitted`,
      };
    }

    const [updated] = await this.db
      .update(cases)
      .set({ status: newStatus, updatedAt: new Date() })
      .where(and(eq(cases.id, caseId), eq(cases.tenantId, this.tenantId)))
      .returning();

    await writeAuditEvent({
      tenantId: this.tenantId,
      entityType: 'case',
      entityId: caseId,
      action: `transition:${currentStatus}→${newStatus}`,
      actorId,
      actorOpenId,
      previousState: JSON.stringify({ status: currentStatus }),
      nextState: JSON.stringify({ status: newStatus }),
    });

    return { ok: true, value: updated };
  }

  // ─── Bundle eligibility ─────────────────────────────────────────────────────

  async canGenerateBundle(caseId: number): Promise<{ eligible: boolean; reason?: string }> {
    const [caseRow] = await this.db
      .select()
      .from(cases)
      .where(and(eq(cases.id, caseId), eq(cases.tenantId, this.tenantId)))
      .limit(1);

    if (!caseRow) return { eligible: false, reason: 'Case not found' };

    if (caseRow.status === 'on_hold') {
      return { eligible: false, reason: 'Case is on hold — resolve before generating bundle' };
    }

    // Must have at least one document approved for bundle
    const docs = await this.db
      .select()
      .from(documents)
      .where(
        and(
          eq(documents.caseId, caseId),
          eq(documents.tenantId, this.tenantId),
          eq(documents.approvedForBundle, 1),
        ),
      );

    if (docs.length === 0) {
      return {
        eligible: false,
        reason: 'No documents approved for bundle — approve at least one document first',
      };
    }

    return { eligible: true };
  }

  // ─── Validate allocation assignment ─────────────────────────────────────────

  async validateAllocationAssignment(caseId: number, clerkId: number): Promise<Result<true>> {
    const [caseRow] = await this.db
      .select()
      .from(cases)
      .where(and(eq(cases.id, caseId), eq(cases.tenantId, this.tenantId)))
      .limit(1);

    if (!caseRow) return { ok: false, error: 'Case not found' };
    if (caseRow.status === 'closed') {
      return { ok: false, error: 'Cannot allocate tasks to a closed case' };
    }

    return { ok: true, value: true };
  }

  // ─── Create bundle record ───────────────────────────────────────────────────

  async initiateBundle(
    caseId: number,
    actorId: number,
    actorOpenId: string,
  ): Promise<Result<{ bundleId: number; orchestrationId: string }>> {
    const eligibility = await this.canGenerateBundle(caseId);
    if (!eligibility.eligible) {
      return { ok: false, error: eligibility.reason ?? 'Not eligible for bundle generation' };
    }

    const orchestrationId = `bundle-${this.tenantId}-${caseId}-${Date.now()}`;

    const [bundle] = await this.db
      .insert(bundles)
      .values({
        tenantId: this.tenantId,
        caseId,
        status: 'pending',
        orchestrationId,
      })
      .returning();

    await writeAuditEvent({
      tenantId: this.tenantId,
      entityType: 'bundle',
      entityId: bundle.id,
      action: 'initiate',
      actorId,
      actorOpenId,
      nextState: JSON.stringify({ caseId, orchestrationId }),
    });

    return { ok: true, value: { bundleId: bundle.id, orchestrationId } };
  }
}

/**
 * Lola Marketing Follow-up Engine
 *
 * Generates the client-facing response message based on the intake outcome.
 * Pure function — decision in, message out.
 */

import type { Decision } from './ultracore.js';

export interface LolaResponse {
  message: string;
  callToAction: string;
  tone: 'urgent' | 'reassuring' | 'standard' | 'rejection';
  nextStep: string;
}

export function lolaFollowUp(input: {
  name: string;
  issueType: string;
  urgency: string;
  decision: Decision;
  riskScore: number;
}): LolaResponse {
  const { name, issueType, decision, riskScore } = input;
  const firstName = name.trim().split(' ')[0];

  switch (decision) {
    case 'ESCALATE':
      return {
        message: `Hi ${firstName}, your ${issueType} matter has been flagged as high priority (risk score: ${riskScore}/100). A senior solicitor has been notified and will contact you within the hour. Please keep your phone available.`,
        callToAction: 'A solicitor will call you shortly',
        tone: 'urgent',
        nextStep: 'Human review — expected within 1 hour',
      };

    case 'MODIFY':
      return {
        message: `Hi ${firstName}, we've received your ${issueType} enquiry. Your matter has been scored at ${riskScore}/100 and requires a brief solicitor review before we proceed. You'll receive a confirmation within 24 hours.`,
        callToAction: 'Check your email for next steps',
        tone: 'reassuring',
        nextStep: 'Solicitor review — expected within 24 hours',
      };

    case 'DENY':
      return {
        message: `Hi ${firstName}, we weren't able to process your ${issueType || 'enquiry'} as submitted. Please complete all required fields and resubmit. If you need help, call our intake line.`,
        callToAction: 'Please resubmit with full details',
        tone: 'rejection',
        nextStep: 'Resubmission required',
      };

    case 'ALLOW':
    default:
      return {
        message: `Hi ${firstName}, your ${issueType} intake has been successfully created (risk score: ${riskScore}/100). Lunar has assessed your matter as standard priority and it's now queued for matter creation.`,
        callToAction: 'Your matter reference will arrive by email',
        tone: 'standard',
        nextStep: 'Matter creation — automated, within 15 minutes',
      };
  }
}

/**
 * Lunar Legal Triage Engine
 *
 * Pure deterministic function — no IO, no side effects.
 * Scores a client's description and returns a risk profile.
 * AI layer sits on top of this; it never replaces it.
 */

export interface TriageResult {
  riskScore: number;           // 0–100
  urgency: 'normal' | 'high' | 'critical';
  flags: string[];             // keywords that contributed to the score
  scoreBreakdown: { signal: string; weight: number }[];
}

// Each signal adds weight to the base score of 20
const SIGNALS: [string, number][] = [
  // Court & legal process
  ['court',           25],
  ['tribunal',        25],
  ['injunction',      30],
  ['hearing',         20],
  ['judgment',        20],

  // Time pressure
  ['deadline',        20],
  ['urgent',          15],
  ['today',           10],
  ['tomorrow',        10],
  ['expire',          20],

  // High-stakes situations
  ['eviction',        30],
  ['repossession',    30],
  ['arrest',          40],
  ['criminal',        40],
  ['custody',         30],
  ['restraining',     35],

  // Serious offences
  ['fraud',           35],
  ['threat',          25],
  ['violence',        35],
  ['harassment',      25],
  ['discrimination',  25],
  ['abuse',           30],

  // Financial
  ['bankruptcy',      20],
  ['insolvency',      20],
  ['debt',            15],
  ['repayment',       10],

  // Civil
  ['divorce',         15],
  ['employment',      10],
  ['contract',        10],
  ['dispute',         10],
  ['damages',         15],
];

export function lunarTriage(description: string): TriageResult {
  const lower = description.toLowerCase();
  const scoreBreakdown: { signal: string; weight: number }[] = [];
  const flags: string[] = [];
  let score = 20;

  for (const [keyword, weight] of SIGNALS) {
    if (lower.includes(keyword)) {
      score += weight;
      flags.push(keyword);
      scoreBreakdown.push({ signal: keyword, weight });
    }
  }

  const riskScore = Math.min(score, 100);
  const urgency: TriageResult['urgency'] =
    riskScore >= 80 ? 'critical' : riskScore >= 50 ? 'high' : 'normal';

  return { riskScore, urgency, flags, scoreBreakdown };
}

import { eq } from 'drizzle-orm';
import type { ClerkAllocation } from '../drizzle/schema';
import { clerkAllocations } from '../drizzle/schema';
import { getDb, writeAuditEvent } from '../trpc/db';
import { ServiceBusClient } from '../services/serviceBus';
import { ClerkOSEngine } from './clerkOS.engine';

// ─── Queue item payload sent via Service Bus ──────────────────────────────────

export type QueueItemPayload = {
  type: 'bundle_generate' | 'case_transition' | 'allocation_escalate';
  tenantId: string;
  caseId: number;
  actorId: number;
  actorOpenId: string;
  // type-specific fields
  targetStatus?: string;
  bundleId?: number;
  allocationId?: number;
};

// ─── SystemSpine ──────────────────────────────────────────────────────────────

export class SystemSpine {
  /**
   * Central dispatcher — called by the Service Bus consumer or directly
   * in test/development when the queue is unavailable.
   */
  async handleQueueItem(payload: QueueItemPayload): Promise<void> {
    const db = await getDb();
    if (!db) {
      console.warn('[SystemSpine] Database not available — skipping queue item');
      return;
    }

    // Always create the engine scoped to the tenant
    const engine = new ClerkOSEngine(db, payload.tenantId);

    switch (payload.type) {
      case 'bundle_generate':
        await this.handleBundleGenerate(engine, payload);
        break;

      case 'case_transition':
        await this.handleCaseTransition(engine, payload);
        break;

      case 'allocation_escalate':
        await this.handleAllocationEscalation(db, payload);
        break;

      default:
        console.warn('[SystemSpine] Unknown queue item type:', (payload as { type: string }).type);
    }
  }

  // ─── Bundle generation ──────────────────────────────────────────────────────

  private async handleBundleGenerate(
    engine: ClerkOSEngine,
    payload: QueueItemPayload,
  ): Promise<void> {
    const result = await engine.initiateBundle(
      payload.caseId,
      payload.actorId,
      payload.actorOpenId,
    );

    if (result.ok === false) {
      console.error('[SystemSpine] Bundle initiation failed:', result.error);
      return;
    }

    // Enqueue to Azure Service Bus for Durable Functions processing
    await ServiceBusClient.send('clerkos-bundles', {
      bundleId: result.value.bundleId,
      orchestrationId: result.value.orchestrationId,
      tenantId: payload.tenantId,
      caseId: payload.caseId,
    });

    console.log(
      `[SystemSpine] Bundle ${result.value.bundleId} queued for orchestration (${result.value.orchestrationId})`,
    );
  }

  // ─── Case transition ────────────────────────────────────────────────────────

  private async handleCaseTransition(
    engine: ClerkOSEngine,
    payload: QueueItemPayload,
  ): Promise<void> {
    if (!payload.targetStatus) return;

    const result = await engine.transitionCase(
      payload.caseId,
      payload.targetStatus as import('./clerkOS.engine').CaseStatus,
      payload.actorId,
      payload.actorOpenId,
    );

    if (result.ok === false) {
      console.error('[SystemSpine] Case transition failed:', result.error);
    }
  }

  // ─── Allocation escalation ──────────────────────────────────────────────────

  private async handleAllocationEscalation(
    db: Awaited<ReturnType<typeof getDb>>,
    payload: QueueItemPayload,
  ): Promise<void> {
    if (!db || !payload.allocationId) return;

    const [allocation] = await db
      .select()
      .from(clerkAllocations)
      .where(eq(clerkAllocations.id, payload.allocationId))
      .limit(1);

    if (!allocation || allocation.tenantId !== payload.tenantId) return;

    // Escalate: bump priority to 'urgent' if overdue
    const today = new Date().toISOString().split('T')[0];
    if (allocation.dueDate && allocation.dueDate < today && allocation.priority !== 'urgent') {
      await db
        .update(clerkAllocations)
        .set({ priority: 'urgent', updatedAt: new Date() })
        .where(eq(clerkAllocations.id, payload.allocationId));

      await writeAuditEvent({
        tenantId: payload.tenantId,
        entityType: 'allocation',
        entityId: payload.allocationId,
        action: 'escalate:urgent',
        actorId: payload.actorId,
        actorOpenId: payload.actorOpenId,
        metadata: JSON.stringify({ reason: 'overdue', dueDate: allocation.dueDate }),
      });
    }
  }
}

// ─── Singleton ────────────────────────────────────────────────────────────────

export const systemSpine = new SystemSpine();

/**
 * UltraCore Decision Gate
 *
 * Pure deterministic gate — single source of truth for intake decisions.
 * Every intake MUST pass through this gate. No exceptions.
 *
 * Decision hierarchy (evaluated top-down, first match wins):
 *   ESCALATE → immediate human review required
 *   DENY     → intake cannot proceed as submitted
 *   MODIFY   → intake can proceed but needs solicitor review first
 *   ALLOW    → standard intake, proceed to matter creation
 */

export type Decision = 'ALLOW' | 'MODIFY' | 'DENY' | 'ESCALATE';

export interface GateResult {
  decision: Decision;
  reason: string;
  rules: string[];  // every rule that was evaluated (for audit trail)
}

interface GateInput {
  issueType: string;
  urgency: 'normal' | 'high' | 'critical';
  riskScore: number;
  description?: string;
}

export function ultraCoreGate(input: GateInput): GateResult {
  const rules: string[] = [];

  // ── Rule 1: Critical risk score → always escalate ────────────────────────
  rules.push(`R1: riskScore=${input.riskScore} ${input.riskScore >= 80 ? '≥80 → ESCALATE' : '<80 → continue'}`);
  if (input.riskScore >= 80) {
    return { decision: 'ESCALATE', reason: `Risk score ${input.riskScore}/100 exceeds critical threshold (80)`, rules };
  }

  // ── Rule 2: Critical urgency → escalate ─────────────────────────────────
  rules.push(`R2: urgency=${input.urgency} ${input.urgency === 'critical' ? '→ ESCALATE' : '→ continue'}`);
  if (input.urgency === 'critical') {
    return { decision: 'ESCALATE', reason: 'Matter flagged as critical urgency by Lunar triage', rules };
  }

  // ── Rule 3: Missing or invalid issue type → deny ─────────────────────────
  const hasIssueType = input.issueType && input.issueType.trim().length >= 2;
  rules.push(`R3: issueType="${input.issueType}" ${hasIssueType ? '→ continue' : '→ DENY'}`);
  if (!hasIssueType) {
    return { decision: 'DENY', reason: 'Issue type must be provided (minimum 2 characters)', rules };
  }

  // ── Rule 4: Description too short → deny ────────────────────────────────
  const descLength = input.description?.trim().length ?? 0;
  rules.push(`R4: descriptionLength=${descLength} ${descLength < 10 ? '→ DENY' : '→ continue'}`);
  if (descLength < 10) {
    return { decision: 'DENY', reason: 'Description too short — please provide more detail (minimum 10 characters)', rules };
  }

  // ── Rule 5: Elevated risk → modify (solicitor review) ───────────────────
  rules.push(`R5: riskScore=${input.riskScore} ${input.riskScore >= 50 ? '≥50 → MODIFY' : '<50 → continue'}`);
  if (input.riskScore >= 50) {
    return { decision: 'MODIFY', reason: `Elevated risk score (${input.riskScore}/100) — solicitor review required before matter creation`, rules };
  }

  // ── Rule 6: High urgency (non-critical) → modify ────────────────────────
  rules.push(`R6: urgency=${input.urgency} ${input.urgency === 'high' ? '→ MODIFY' : '→ continue'}`);
  if (input.urgency === 'high') {
    return { decision: 'MODIFY', reason: 'High-urgency matter — expedited review recommended', rules };
  }

  // ── Default: standard intake ─────────────────────────────────────────────
  rules.push('R7: all checks passed → ALLOW');
  return { decision: 'ALLOW', reason: 'Standard intake — proceed to matter creation', rules };
}

/**
 * VaultLine Audit Engine
 *
 * Tamper-evident audit log using SHA-256 content hashing.
 * Every intake event is hashed at the point of creation.
 * The hash is stored alongside the payload — any modification
 * of either the payload OR the hash is detectable.
 */

import crypto from 'crypto';

export interface VaultEvent {
  intakeId: string;
  eventType: string;
  payload: unknown;
  hash: string;
  createdAt: string;
}

export function createVaultHash(payload: unknown): string {
  return crypto
    .createHash('sha256')
    .update(JSON.stringify(payload))
    .digest('hex');
}

export function buildVaultEvent(
  intakeId: string,
  eventType: string,
  payload: unknown,
): VaultEvent {
  const createdAt = new Date().toISOString();
  // Hash includes all fields so any tampering is detectable
  const hash = createVaultHash({ intakeId, eventType, payload, createdAt });
  return { intakeId, eventType, payload, hash, createdAt };
}

export function verifyVaultEvent(event: VaultEvent): boolean {
  const { intakeId, eventType, payload, createdAt, hash } = event;
  const expected = createVaultHash({ intakeId, eventType, payload, createdAt });
  return expected === hash;
}

import {
  BlobServiceClient,
  generateBlobSASQueryParameters,
  BlobSASPermissions,
  StorageSharedKeyCredential,
} from '@azure/storage-blob';

// ─── Config ───────────────────────────────────────────────────────────────────

const ACCOUNT_NAME = process.env.AZURE_STORAGE_ACCOUNT ?? '';
const ACCOUNT_KEY = process.env.AZURE_STORAGE_KEY ?? '';
const CONNECTION_STRING = process.env.AZURE_STORAGE_CONNECTION_STRING ?? '';
const CONTAINER = process.env.AZURE_STORAGE_CONTAINER ?? 'clerkos-documents';

// ─── Lazy client ──────────────────────────────────────────────────────────────

let _blobClient: BlobServiceClient | null = null;

function getClient(): BlobServiceClient | null {
  if (_blobClient) return _blobClient;
  if (CONNECTION_STRING) {
    try {
      _blobClient = BlobServiceClient.fromConnectionString(CONNECTION_STRING);
      return _blobClient;
    } catch (err) {
      console.warn('[BlobStorage] Failed to create client:', err);
    }
  }
  return null;
}

// ─── Path convention ─────────────────────────────────────────────────────────
// tenants/{tenantId}/cases/{caseId}/documents/{documentId}/v{version}

export function buildBlobPath(
  tenantId: string,
  caseId: number,
  documentId: number,
  version: number,
  fileName: string,
): string {
  return `tenants/${tenantId}/cases/${caseId}/documents/${documentId}/v${version}/${fileName}`;
}

// ─── Public API ───────────────────────────────────────────────────────────────

export const BlobStorage = {
  /**
   * Upload a Buffer or stream to blob storage.
   * Returns the blob URL or null if storage is not configured.
   */
  async upload(blobPath: string, data: Buffer, mimeType: string): Promise<string | null> {
    const client = getClient();
    if (!client) {
      console.debug('[BlobStorage] Not configured — upload skipped for:', blobPath);
      return null;
    }

    const container = client.getContainerClient(CONTAINER);
    await container.createIfNotExists({ access: 'blob' });

    const blob = container.getBlockBlobClient(blobPath);
    await blob.upload(data, data.length, {
      blobHTTPHeaders: { blobContentType: mimeType },
    });

    return blob.url;
  },

  /**
   * Generate a short-lived SAS token URL for direct client uploads.
   * Expires in the given number of minutes (default 15).
   */
  generateUploadSasUrl(blobPath: string, expiresInMinutes = 15): string | null {
    if (!ACCOUNT_NAME || !ACCOUNT_KEY) {
      console.debug('[BlobStorage] Not configured — SAS URL not generated');
      return null;
    }

    const credential = new StorageSharedKeyCredential(ACCOUNT_NAME, ACCOUNT_KEY);
    const expiresOn = new Date();
    expiresOn.setMinutes(expiresOn.getMinutes() + expiresInMinutes);

    const sas = generateBlobSASQueryParameters(
      {
        containerName: CONTAINER,
        blobName: blobPath,
        permissions: BlobSASPermissions.parse('cw'), // create + write
        expiresOn,
      },
      credential,
    );

    return `https://${ACCOUNT_NAME}.blob.core.windows.net/${CONTAINER}/${blobPath}?${sas.toString()}`;
  },

  /**
   * Generate a read SAS URL for secure client downloads.
   */
  generateReadSasUrl(blobPath: string, expiresInMinutes = 60): string | null {
    if (!ACCOUNT_NAME || !ACCOUNT_KEY) return null;

    const credential = new StorageSharedKeyCredential(ACCOUNT_NAME, ACCOUNT_KEY);
    const expiresOn = new Date();
    expiresOn.setMinutes(expiresOn.getMinutes() + expiresInMinutes);

    const sas = generateBlobSASQueryParameters(
      {
        containerName: CONTAINER,
        blobName: blobPath,
        permissions: BlobSASPermissions.parse('r'),
        expiresOn,
      },
      credential,
    );

    return `https://${ACCOUNT_NAME}.blob.core.windows.net/${CONTAINER}/${blobPath}?${sas.toString()}`;
  },
};

import fetch from 'node-fetch';

/**
 * Companies House API Service
 * Real-time integration with Companies House API
 *
 * API Documentation: https://developer-specs.company-information.service.gov.uk/
 */

const CH_API_BASE = 'https://api.company-information.service.gov.uk';
const CH_STREAM_BASE = 'https://stream.companieshouse.gov.uk';
const CH_API_KEY = process.env.COMPANIES_HOUSE_API_KEY;

interface CompanyProfile {
  companyNumber: string;
  companyName: string;
  companyStatus: string;
  companyStatusDetail?: string;
  dateOfCreation: string;
  jurisdiction: string;
  sicCodes?: string[];
  hasBeenLiquidated: boolean;
  type: string;
  hasInsolvencyHistory: boolean;
  registeredOfficeAddress: {
    addressLine1?: string;
    addressLine2?: string;
    locality?: string;
    region?: string;
    postalCode?: string;
    country?: string;
  };
  accounts?: {
    nextAccounts?: {
      periodEndOn: string;
      periodStartOn: string;
      dueOn: string;
      overdue: boolean;
    };
    lastAccounts?: {
      madeUpTo: string;
      type: string;
    };
    accountingReferenceDate?: {
      day: string;
      month: string;
    };
  };
  confirmationStatement?: {
    nextDue: string;
    nextMadeUpTo: string;
    overdue: boolean;
    lastMadeUpTo?: string;
  };
  links: {
    self: string;
    filingHistory?: string;
    officers?: string;
    charges?: string;
  };
}

interface FilingHistoryItem {
  date: string;
  type: string;
  description: string;
  category: string;
  actionDate?: string;
  barcode?: string;
  links: {
    self: string;
    documentMetadata?: string;
  };
}

interface ComplianceStatus {
  companyNumber: string;
  companyName: string;
  status: 'compliant' | 'warning' | 'overdue';
  overdueFilings: FilingDeadline[];
  upcomingDeadlines: FilingDeadline[];
  lastFiling?: {
    type: string;
    date: string;
  };
  accountsStatus: {
    nextDue: string;
    overdue: boolean;
    daysUntilDue: number;
  };
  confirmationStatementStatus: {
    nextDue: string;
    overdue: boolean;
    daysUntilDue: number;
  };
  riskLevel: 'none' | 'low' | 'medium' | 'high';
  penalties?: {
    estimated: number;
    description: string;
  }[];
}

interface FilingDeadline {
  type: 'accounts' | 'confirmation-statement' | 'annual-return' | 'other';
  description: string;
  dueDate: string;
  daysUntilDue: number;
  overdue: boolean;
  penaltyRisk?: number;
}

export class CompaniesHouseService {
  private apiKey: string;

  constructor() {
    this.apiKey = CH_API_KEY ?? '';
  }

  /**
   * Get authentication headers for Companies House API
   */
  private getAuthHeaders() {
    return {
      'Authorization': `Basic ${Buffer.from(this.apiKey + ':').toString('base64')}`,
      'Content-Type': 'application/json',
    };
  }

  /**
   * Fetch company profile from Companies House
   */
  async getCompanyProfile(companyNumber: string): Promise<CompanyProfile | null> {
    const cleanNumber = companyNumber.replace(/\s/g, '').toUpperCase();
    const maxRetries = 3;
    let lastError: Error | null = null;

    for (let attempt = 1; attempt <= maxRetries; attempt++) {
      try {
        const response = await fetch(`${CH_API_BASE}/company/${cleanNumber}`, {
          headers: this.getAuthHeaders(),
        });

        if (!response.ok) {
          if (response.status === 404) {
            return null; // Company not found
          }
          if (response.status === 401) {
            throw new Error('Invalid Companies House API key');
          }
          if (response.status === 429) {
            // Rate limited - wait and retry
            if (attempt < maxRetries) {
              await this.delay(2000 * attempt);
              continue;
            }
            throw new Error('Companies House API rate limit exceeded');
          }
          throw new Error(`Companies House API error: ${response.status}`);
        }

        const data = await response.json() as CompanyProfile;
        console.log(`📊 Company profile fetched: ${data.companyName}`);
        return data;
      } catch (error) {
        lastError = error as Error;
        if (attempt < maxRetries && this.isRetryableError(error)) {
          console.log(`⏳ Retry attempt ${attempt}/${maxRetries} for ${cleanNumber}`);
          await this.delay(1000 * attempt);
          continue;
        }
        break;
      }
    }

    console.error('Error fetching company profile:', lastError);
    throw lastError;
  }

  /**
   * Check if error is retryable
   */
  private isRetryableError(error: any): boolean {
    if (error.message?.includes('rate limit')) return false;
    if (error.message?.includes('Invalid')) return false;
    return true; // Network errors are retryable
  }

  /**
   * Delay helper for retries
   */
  private delay(ms: number): Promise<void> {
    return new Promise(resolve => setTimeout(resolve, ms));
  }

  /**
   * Get filing history for a company
   */
  async getFilingHistory(companyNumber: string, limit: number = 20): Promise<FilingHistoryItem[]> {
    try {
      const cleanNumber = companyNumber.replace(/\s/g, '').toUpperCase();
      const response = await fetch(
        `${CH_API_BASE}/company/${cleanNumber}/filing-history?items_per_page=${limit}`,
        { headers: this.getAuthHeaders() }
      );

      if (!response.ok) {
        if (response.status === 404) {
          console.log(`📈 No filing history for ${cleanNumber}`);
          return []; // No filing history
        }
        throw new Error(`Failed to fetch filing history: ${response.status}`);
      }

      const data = await response.json() as any;
      const items = data.items || [];
      console.log(`📈 Filing history retrieved: ${items.length} filings`);
      return items;
    } catch (error) {
      console.error('Error fetching filing history:', error);
      // Don't throw - filing history is not critical
      return [];
    }
  }

  /**
   * Calculate compliance status with deadlines and risk assessment
   */
  async getComplianceStatus(companyNumber: string): Promise<ComplianceStatus> {
    const profile = await this.getCompanyProfile(companyNumber);

    if (!profile) {
      throw new Error('Company not found');
    }

    const filingHistory = await this.getFilingHistory(companyNumber, 5);
    const overdueFilings: FilingDeadline[] = [];
    const upcomingDeadlines: FilingDeadline[] = [];
    const penalties: { estimated: number; description: string }[] = [];

    // Check accounts status
    if (profile.accounts?.nextAccounts) {
      const accountsDueDate = new Date(profile.accounts.nextAccounts.dueOn);
      const daysUntilDue = this.calculateDaysUntil(accountsDueDate);
      const overdue = profile.accounts.nextAccounts.overdue || daysUntilDue < 0;

      const accountsDeadline: FilingDeadline = {
        type: 'accounts',
        description: 'Annual Accounts',
        dueDate: profile.accounts.nextAccounts.dueOn,
        daysUntilDue,
        overdue,
        penaltyRisk: overdue ? this.calculateAccountsPenalty(Math.abs(daysUntilDue)) : 0,
      };

      if (overdue) {
        overdueFilings.push(accountsDeadline);
        penalties.push({
          estimated: accountsDeadline.penaltyRisk!,
          description: `Late filing penalty for accounts (${Math.abs(daysUntilDue)} days overdue)`,
        });
      } else if (daysUntilDue <= 30) {
        upcomingDeadlines.push(accountsDeadline);
      }
    }

    // Check confirmation statement status
    if (profile.confirmationStatement?.nextDue) {
      const csDueDate = new Date(profile.confirmationStatement.nextDue);
      const daysUntilDue = this.calculateDaysUntil(csDueDate);
      const overdue = profile.confirmationStatement.overdue || daysUntilDue < 0;

      const csDeadline: FilingDeadline = {
        type: 'confirmation-statement',
        description: 'Confirmation Statement',
        dueDate: profile.confirmationStatement.nextDue,
        daysUntilDue,
        overdue,
        penaltyRisk: overdue ? this.calculateCSPenalty(Math.abs(daysUntilDue)) : 0,
      };

      if (overdue) {
        overdueFilings.push(csDeadline);
        penalties.push({
          estimated: csDeadline.penaltyRisk!,
          description: `Late filing penalty for confirmation statement (${Math.abs(daysUntilDue)} days overdue)`,
        });
      } else if (daysUntilDue <= 30) {
        upcomingDeadlines.push(csDeadline);
      }
    }

    // Determine overall status and risk level
    let status: 'compliant' | 'warning' | 'overdue' = 'compliant';
    let riskLevel: 'none' | 'low' | 'medium' | 'high' = 'none';

    if (overdueFilings.length > 0) {
      const maxOverdueDays = Math.max(...overdueFilings.map(f => Math.abs(f.daysUntilDue)));
      status = 'overdue';

      // Risk level based on days overdue
      if (maxOverdueDays > 90) {
        riskLevel = 'high'; // 90+ days = high risk (max penalties)
      } else if (maxOverdueDays > 30) {
        riskLevel = 'high'; // 30-90 days = high risk
      } else {
        riskLevel = 'medium'; // 1-30 days = medium risk
      }
    } else if (upcomingDeadlines.some(d => d.daysUntilDue <= 7)) {
      // Deadline within 7 days
      status = 'warning';
      riskLevel = 'medium';
    } else if (upcomingDeadlines.some(d => d.daysUntilDue <= 14)) {
      // Deadline within 14 days
      status = 'warning';
      riskLevel = 'low';
    } else if (upcomingDeadlines.length > 0) {
      // Deadlines exist but >14 days away
      status = 'compliant';
      riskLevel = 'none';
    } else {
      // Fully compliant with no upcoming deadlines
      status = 'compliant';
      riskLevel = 'none';
    }

    const lastFiling = filingHistory[0] ? {
      type: filingHistory[0].description,
      date: filingHistory[0].date,
    } : undefined;

    return {
      companyNumber: profile.companyNumber,
      companyName: profile.companyName,
      status,
      overdueFilings,
      upcomingDeadlines,
      lastFiling,
      accountsStatus: {
        nextDue: profile.accounts?.nextAccounts?.dueOn || 'N/A',
        overdue: profile.accounts?.nextAccounts?.overdue || false,
        daysUntilDue: profile.accounts?.nextAccounts?.dueOn
          ? this.calculateDaysUntil(new Date(profile.accounts.nextAccounts.dueOn))
          : 999,
      },
      confirmationStatementStatus: {
        nextDue: profile.confirmationStatement?.nextDue || 'N/A',
        overdue: profile.confirmationStatement?.overdue || false,
        daysUntilDue: profile.confirmationStatement?.nextDue
          ? this.calculateDaysUntil(new Date(profile.confirmationStatement.nextDue))
          : 999,
      },
      riskLevel,
      penalties: penalties.length > 0 ? penalties : undefined,
    };
  }

  /**
   * Calculate days until a deadline
   */
  private calculateDaysUntil(date: Date): number {
    const now = new Date();
    const diffTime = date.getTime() - now.getTime();
    return Math.ceil(diffTime / (1000 * 60 * 60 * 24));
  }

  /**
   * Calculate penalty for late accounts filing
   * Based on Companies House penalty structure
   */
  private calculateAccountsPenalty(daysOverdue: number): number {
    if (daysOverdue <= 30) return 150; // £150 for up to 1 month late
    if (daysOverdue <= 90) return 375; // £375 for up to 3 months late
    if (daysOverdue <= 180) return 750; // £750 for up to 6 months late
    return 1500; // £1,500 for more than 6 months late
  }

  /**
   * Calculate penalty for late confirmation statement
   * Note: Late filing can result in prosecution. Penalties vary.
   */
  private calculateCSPenalty(daysOverdue: number): number {
    // Confirmation statements don't have automatic fixed penalties like accounts
    // However, late filing is a criminal offense that can lead to:
    // - Prosecution and fines up to £5,000
    // - Director disqualification
    //
    // For estimation purposes, we use a graduated scale:
    if (daysOverdue <= 14) return 0; // Grace period
    if (daysOverdue <= 28) return 150; // £150 (minor delay)
    if (daysOverdue <= 90) return 500; // £500 (significant delay)
    return 1000; // £1,000+ (prosecution risk)
  }

  /**
   * Subscribe to Companies House streaming API for real-time updates
   * Returns event stream for company changes
   */
  async subscribeToCompanyUpdates(companyNumber: string): Promise<NodeJS.ReadableStream> {
    const cleanNumber = companyNumber.replace(/\s/g, '').toUpperCase();

    // Companies House Streaming API endpoint
    const streamUrl = `${CH_STREAM_BASE}/companies/${cleanNumber}`;

    const response = await fetch(streamUrl, {
      headers: this.getAuthHeaders(),
    });

    if (!response.ok) {
      throw new Error(`Streaming API error: ${response.status}`);
    }

    return response.body as unknown as NodeJS.ReadableStream;
  }

  /**
   * Validate company number format
   */
  validateCompanyNumber(companyNumber: string): boolean {
    // UK company numbers are typically 8 characters (with leading zeros)
    // Can be 2 letters followed by 6 digits, or 8 digits
    const cleaned = companyNumber.replace(/\s/g, '').toUpperCase();
    return /^([A-Z]{2}\d{6}|\d{8})$/.test(cleaned);
  }

  /**
   * Format company number (add leading zeros if needed)
   */
  formatCompanyNumber(companyNumber: string): string {
    const cleaned = companyNumber.replace(/\s/g, '').toUpperCase();

    // If it's all digits and less than 8 characters, pad with zeros
    if (/^\d+$/.test(cleaned) && cleaned.length < 8) {
      return cleaned.padStart(8, '0');
    }

    return cleaned;
  }
}

