import { router } from './_core/trpc';
import { allocationsRouter } from './routers/allocations';
import { authRouter } from './routers/auth';
import { casesRouter } from './routers/cases';
import { dashboardRouter } from './routers/dashboard';
import { diaryRouter } from './routers/diary';
import { documentsRouter } from './routers/documents';
import { hearingsRouter } from './routers/hearings';
import { lunarRouter } from './routers/lunar';

export const appRouter = router({
  auth: authRouter,
  cases: casesRouter,
  hearings: hearingsRouter,
  documents: documentsRouter,
  allocations: allocationsRouter,
  diary: diaryRouter,
  dashboard: dashboardRouter,
  lunar: lunarRouter,
});

export type AppRouter = typeof appRouter;

import { createRemoteJWKSet, jwtVerify } from 'jose';
import type { Request } from 'express';
import type { Tenant } from '../../drizzle/schema';

// ─── Azure AD B2C config (from env) ──────────────────────────────────────────

const B2C_TENANT = process.env.AZURE_B2C_TENANT_NAME ?? '';
const B2C_POLICY = process.env.AZURE_B2C_POLICY ?? 'B2C_1_signupsignin';
const B2C_CLIENT_ID = process.env.AZURE_B2C_CLIENT_ID ?? '';

function getJwksUri(): string {
  return `https://${B2C_TENANT}.b2clogin.com/${B2C_TENANT}.onmicrosoft.com/${B2C_POLICY}/discovery/v2.0/keys`;
}

function getIssuer(): string {
  return `https://${B2C_TENANT}.b2clogin.com/${process.env.AZURE_B2C_TENANT_ID ?? B2C_TENANT}/v2.0/`;
}

// Lazy JWKS set (cached in-process)
let _jwks: ReturnType<typeof createRemoteJWKSet> | null = null;
function getJwks() {
  if (!_jwks && B2C_TENANT) {
    _jwks = createRemoteJWKSet(new URL(getJwksUri()));
  }
  return _jwks;
}

// ─── Token payload shape ──────────────────────────────────────────────────────

export type B2CTokenClaims = {
  oid: string;        // Azure object ID — used as openId
  emails?: string[];  // Email addresses
  name?: string;
  given_name?: string;
  family_name?: string;
  extension_tenantSlug?: string; // Custom attribute for tenant (optional)
  roles?: string[];   // App roles
};

export type VerifiedAuthUser = {
  openId: string;
  email: string | null;
  name: string | null;
};

// ─── Verify Azure AD B2C JWT ──────────────────────────────────────────────────

export async function verifyB2CToken(token: string): Promise<VerifiedAuthUser | null> {
  const jwks = getJwks();
  if (!jwks) return null;

  try {
    const { payload } = await jwtVerify(token, jwks, {
      issuer: getIssuer(),
      audience: B2C_CLIENT_ID || undefined,
    });

    const claims = payload as unknown as B2CTokenClaims;

    return {
      openId: claims.oid,
      email: claims.emails?.[0] ?? null,
      name: claims.name ?? ([claims.given_name, claims.family_name].filter(Boolean).join(' ') || null),
    };
  } catch {
    return null;
  }
}

// ─── Extract auth user from Express request ───────────────────────────────────

export async function getUserFromRequest(req: Request): Promise<VerifiedAuthUser | null> {
  // 1. Try Azure AD B2C Bearer token
  const authHeader = req.headers.authorization;
  if (authHeader?.startsWith('Bearer ')) {
    const token = authHeader.slice(7);
    const user = await verifyB2CToken(token);
    if (user) return user;
  }

  // 2. Dev/test fallback: x-user-open-id header (only in non-production)
  if (process.env.NODE_ENV !== 'production') {
    const openId = req.headers['x-user-open-id'] as string | undefined;
    if (openId) {
      return {
        openId,
        email: req.headers['x-user-email'] as string ?? null,
        name: req.headers['x-user-name'] as string ?? null,
      };
    }
  }

  return null;
}

// ─── Resolve tenant from request ─────────────────────────────────────────────

export function getTenantSlugFromRequest(req: Request): string | null {
  // 1. Explicit header (e.g. X-Tenant: acme)
  const headerSlug = req.headers['x-tenant'] as string | undefined;
  if (headerSlug) return headerSlug.toLowerCase();

  // 2. Subdomain: acme.clerkos.app → slug = acme
  const host = req.headers.host ?? '';
  // Strip port, strip www, take first subdomain part
  const hostOnly = host.split(':')[0];
  const parts = hostOnly.split('.');
  // e.g. acme.clerkos.app → ['acme', 'clerkos', 'app'] → parts.length >= 3
  if (parts.length >= 3 && parts[0] !== 'www') {
    return parts[0].toLowerCase();
  }

  // 3. Dev fallback: DEFAULT_TENANT_SLUG env var
  if (process.env.DEFAULT_TENANT_SLUG) {
    return process.env.DEFAULT_TENANT_SLUG;
  }

  return null;
}

// ─── Tenant lookup helper (imported by context.ts) ───────────────────────────

export type { Tenant };

import type { Request, Response } from 'express';
import type { Tenant } from '../../drizzle/schema';

export type TrpcUser = {
  id: number;
  openId: string;
  email: string | null;
  name: string | null;
  loginMethod: string | null;
  role: string | null;
  createdAt: Date;
  updatedAt: Date;
  lastSignedIn: Date | null;
};

export type TrpcContext = {
  user: TrpcUser | null;
  /** Resolved from subdomain or x-tenant header */
  tenantId: string | null;
  tenant: Tenant | null;
  req: Request;
  res: Pick<Response, 'clearCookie'>;
};

/** Narrowed context available inside authed+tenant procedures */
export type TenantedContext = TrpcContext & {
  user: TrpcUser;
  tenantId: string;
  tenant: Tenant;
};

export const ENV = {
  ownerOpenId: process.env.OWNER_OPEN_ID ?? '',
  databaseUrl: process.env.DATABASE_URL ?? '',
  port: Number(process.env.PORT ?? 3000),
  nodeEnv: process.env.NODE_ENV ?? 'development',
} as const;

import { initTRPC, TRPCError } from '@trpc/server';
import type { TrpcContext } from './context';

const t = initTRPC.context<TrpcContext>().create();

export const router = t.router;
export const middleware = t.middleware;

// ─── Public (no auth) ────────────────────────────────────────────────────────

export const publicProcedure = t.procedure;

// ─── Authenticated (user required) ───────────────────────────────────────────

const isAuthed = t.middleware(({ ctx, next }) => {
  if (!ctx.user) throw new TRPCError({ code: 'UNAUTHORIZED' });
  return next({ ctx: { ...ctx, user: ctx.user } });
});

export const authedProcedure = t.procedure.use(isAuthed);

// ─── Tenant-scoped (user + tenant required) ───────────────────────────────────

const isTenanted = t.middleware(({ ctx, next }) => {
  if (!ctx.user) throw new TRPCError({ code: 'UNAUTHORIZED' });
  if (!ctx.tenantId || !ctx.tenant) {
    throw new TRPCError({
      code: 'FORBIDDEN',
      message: 'Tenant context not resolved. Ensure correct subdomain or x-tenant header.',
    });
  }
  return next({
    ctx: {
      ...ctx,
      user: ctx.user,
      tenantId: ctx.tenantId,
      tenant: ctx.tenant,
    },
  });
});

export const tenantProcedure = t.procedure.use(isTenanted);

// ─── Admin (senior clerk / manager) within a tenant ──────────────────────────

const isAdmin = t.middleware(({ ctx, next }) => {
  if (!ctx.user) throw new TRPCError({ code: 'UNAUTHORIZED' });
  if (!ctx.tenantId || !ctx.tenant) {
    throw new TRPCError({ code: 'FORBIDDEN', message: 'Tenant context not resolved.' });
  }
  if (ctx.user.role !== 'admin (senior clerk / manager)') {
    throw new TRPCError({ code: 'FORBIDDEN', message: 'Admin access required.' });
  }
  return next({
    ctx: {
      ...ctx,
      user: ctx.user,
      tenantId: ctx.tenantId,
      tenant: ctx.tenant,
    },
  });
});

export const adminProcedure = t.procedure.use(isAdmin);

import { and, eq } from 'drizzle-orm';
import { z } from 'zod';
import { clerkAllocations } from '../../drizzle/schema';
import { adminProcedure, tenantProcedure, router } from '../_core/trpc';
import { getAllocationsByCase, getAllocationsByClerk, getDb, getPendingAllocations, writeAuditEvent } from '../db';
import { ClerkOSEngine } from '../../engine/clerkOS.engine';

const priorityEnum = z.enum(['low', 'medium', 'high', 'urgent']);
const statusEnum = z.enum(['pending', 'in_progress', 'completed', 'cancelled']);

export const allocationsRouter = router({
  create: adminProcedure
    .input(
      z.object({
        clerkId: z.number(),
        caseId: z.number(),
        taskType: z.string().min(1),
        priority: priorityEnum.optional().default('medium'),
        dueDate: z
          .string()
          .regex(/^\d{4}-\d{2}-\d{2}$/, 'Date must be YYYY-MM-DD')
          .optional(),
        notes: z.string().optional(),
      }),
    )
    .mutation(async ({ ctx, input }) => {
      const db = await getDb();
      if (!db) throw new Error('Database not available');

      // Engine validates case eligibility before allocating
      const engine = new ClerkOSEngine(db, ctx.tenantId);
      const validation = await engine.validateAllocationAssignment(input.caseId, input.clerkId);
      if (validation.ok === false) throw new Error(validation.error);

      const [created] = await db
        .insert(clerkAllocations)
        .values({
          tenantId: ctx.tenantId,
          caseId: input.caseId,
          clerkId: input.clerkId,
          taskType: input.taskType,
          priority: input.priority,
          dueDate: input.dueDate,
          notes: input.notes,
        })
        .returning();
      await writeAuditEvent({
        tenantId: ctx.tenantId,
        entityType: 'allocation',
        entityId: created.id,
        action: 'create',
        actorId: ctx.user.id,
        actorOpenId: ctx.user.openId,
        nextState: JSON.stringify(created),
      });
      return created;
    }),

  update: adminProcedure
    .input(
      z.object({
        id: z.number(),
        status: statusEnum,
        notes: z.string().optional(),
      }),
    )
    .mutation(async ({ ctx, input }) => {
      const db = await getDb();
      if (!db) throw new Error('Database not available');
      const { id, ...patch } = input;
      const completedAt = patch.status === 'completed' ? new Date() : undefined;
      const [updated] = await db
        .update(clerkAllocations)
        .set({ ...patch, ...(completedAt ? { completedAt } : {}), updatedAt: new Date() })
        .where(and(eq(clerkAllocations.id, id), eq(clerkAllocations.tenantId, ctx.tenantId)))
        .returning();
      await writeAuditEvent({
        tenantId: ctx.tenantId,
        entityType: 'allocation',
        entityId: id,
        action: `status_change:${patch.status}`,
        actorId: ctx.user.id,
        actorOpenId: ctx.user.openId,
        nextState: JSON.stringify(updated),
      });
      return updated;
    }),

  getPending: adminProcedure
    .input(
      z
        .object({
          limit: z.number().int().min(1).max(500).default(100),
          offset: z.number().int().min(0).default(0),
        })
        .optional(),
    )
    .query(async ({ ctx, input }) => {
      const rows = await getPendingAllocations(ctx.tenantId);
      const offset = input?.offset ?? 0;
      const limit = input?.limit ?? 100;
      return rows.slice(offset, offset + limit);
    }),

  getByClerk: tenantProcedure
    .input(z.object({ clerkId: z.number() }))
    .query(async ({ ctx, input }) => getAllocationsByClerk(input.clerkId, ctx.tenantId)),

  getByCase: tenantProcedure
    .input(z.object({ caseId: z.number() }))
    .query(({ ctx, input }) => getAllocationsByCase(input.caseId, ctx.tenantId)),
});

