if (!localStorage.getItem('clerk-open-id')) localStorage.setItem('clerk-open-id', 'admin-user');
if (!localStorage.getItem('clerk-name')) localStorage.setItem('clerk-name', 'Patricia Chen');

const queryClient = new QueryClient({
