// ── Page ──────────────────────────────────────────────────────────────────────

export default function CaseDetail() {
  const params = useParams<{ id: string }>();
  const caseId = Number(params.id);
  const [tab, setTab] = useState<TabId>('overview');
  const utils = trpc.useContext();

  const { data: caseData, isLoading, error } = trpc.cases.getById.useQuery(
    { id: caseId },
    { enabled: !isNaN(caseId), retry: false },
  );

  // Lightweight counts for workflow progress indicators
  const { data: hearings = [] } = trpc.hearings.getByCaseId.useQuery(
    { caseId },
    { enabled: !isNaN(caseId), retry: false },
  );
  const { data: docs = [] } = trpc.documents.getByCaseId.useQuery(
    { caseId },
    { enabled: !isNaN(caseId), retry: false },
  );

  const transitionMutation = trpc.cases.transition.useMutation({
    onSuccess: () => {
      utils.cases.getById.invalidate({ id: caseId });
      toast.success('Status updated');
    },
    onError: (e) => toast.error(e.message),
  });

  if (isLoading) {
    return (
      <ClerkOSLayout>
        <div className="p-6 max-w-5xl mx-auto space-y-4">
          {[1, 2].map((i) => (
            <div key={i} className="bg-white dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-800 p-6 animate-pulse">
              <div className="h-5 bg-slate-200 dark:bg-slate-800 rounded w-1/3 mb-3" />
              <div className="h-3 bg-slate-200 dark:bg-slate-800 rounded w-1/2" />
            </div>
          ))}
        </div>
      </ClerkOSLayout>
    );
  }

  if (error || !caseData) {
    return (
      <ClerkOSLayout>
        <div className="p-6 max-w-5xl mx-auto">
          <DbError />
          <Link href="/cases">
            <button className="mt-4 flex items-center gap-2 text-sm text-slate-500 hover:text-slate-900 dark:hover:text-slate-100">
              <ArrowLeft className="w-4 h-4" /> Back to Cases
            </button>
          </Link>
        </div>
      </ClerkOSLayout>
    );
  }

  const hasHearing = hearings.length > 0;
  const hasDocs = docs.length > 0;
  const hasBundleDoc = docs.some((d) => d.approvedForBundle);

  // Workflow progress
  let workflowStep = -1;
  WORKFLOW.forEach((step, i) => {
    if (step.doneWhen(caseData.status, hasHearing, hasDocs, hasBundleDoc)) workflowStep = i;
  });

  const VALID_NEXT: Record<string, string[]> = {
    open: ['in_progress', 'on_hold', 'closed'],
    in_progress: ['closed', 'on_hold', 'open'],
    on_hold: ['open', 'in_progress', 'closed'],
    closed: ['open'],
  };
  const nextStatuses = VALID_NEXT[caseData.status] ?? [];

  return (
    <ClerkOSLayout>
      <div className="p-6 max-w-5xl mx-auto space-y-5">
        {/* ── Breadcrumb ── */}
        <Link href="/cases">
          <button className="flex items-center gap-1.5 text-sm text-slate-400 hover:text-slate-900 dark:hover:text-slate-100 transition-colors">
            <ArrowLeft className="w-4 h-4" />
            Cases
          </button>
        </Link>

        {/* ── Case header ── */}
        <div className="bg-white dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-800 p-5">
          <div className="flex items-start justify-between gap-4 flex-wrap">
            <div>
              <div className="flex items-center gap-2 mb-1">
                <Scale className="w-4 h-4 text-slate-400" />
                <span className="text-xs text-slate-500 dark:text-slate-400 font-mono">{caseData.referenceNumber}</span>
                <span className={`text-[10px] font-medium px-2 py-0.5 rounded-full ${STATUS_BADGE[caseData.status] ?? ''}`}>
                  {caseData.status.replace('_', ' ')}
                </span>
              </div>
              <h1 className="text-xl font-bold text-slate-900 dark:text-slate-100">{caseData.title}</h1>
              <p className="text-sm text-slate-500 dark:text-slate-400 mt-0.5">{caseData.caseType}</p>
            </div>

            {/* Status transition buttons */}
            <div className="flex items-center gap-2 flex-wrap">
              {nextStatuses.map((s) => (
                <button
                  key={s}
                  onClick={() => transitionMutation.mutate({ id: caseId, status: s as 'open' | 'in_progress' | 'closed' | 'on_hold' })}
                  disabled={transitionMutation.isLoading}
                  className="px-3 py-1.5 text-xs font-medium rounded-lg border border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800 disabled:opacity-40 transition-colors"
                >
                  → {s.replace('_', ' ')}
                </button>
              ))}
            </div>
          </div>

          {/* ── Workflow progress bar ── */}
          <div className="mt-5 pt-4 border-t border-slate-100 dark:border-slate-800">
            <p className="text-[10px] font-semibold text-slate-400 uppercase tracking-wide mb-3">Workflow Progress</p>
            <div className="flex items-center gap-0">
              {WORKFLOW.map((step, i) => {
                const done = i <= workflowStep;
                const active = i === workflowStep + 1;
                return (
                  <div key={step.label} className="flex items-center flex-1 min-w-0">
                    <div className="flex flex-col items-center flex-1">
                      <div className={`w-5 h-5 rounded-full flex items-center justify-center shrink-0 ${
                        done
                          ? 'bg-emerald-500 text-white'
                          : active
                          ? 'bg-blue-600 text-white ring-2 ring-blue-300 dark:ring-blue-800'
                          : 'bg-slate-200 dark:bg-slate-800 text-slate-400'
                      }`}>
                        {done ? (
                          <CheckCircle2 className="w-3.5 h-3.5" />
                        ) : (
                          <span className="text-[9px] font-bold">{i + 1}</span>
                        )}
                      </div>
                      <p className={`text-[9px] mt-1 text-center leading-tight ${
                        done ? 'text-emerald-600 dark:text-emerald-400' : active ? 'text-blue-600 dark:text-blue-400 font-semibold' : 'text-slate-400'
                      }`}>
                        {step.label}
                      </p>
                    </div>
                    {i < WORKFLOW.length - 1 && (
                      <div className={`flex-1 h-px mx-1 -mt-4 ${done ? 'bg-emerald-400' : 'bg-slate-200 dark:bg-slate-700'}`} />
                    )}
                  </div>
                );
              })}
            </div>
          </div>
        </div>

        {/* ── Stat pills ── */}
        <div className="grid grid-cols-3 gap-3 sm:grid-cols-5">
          {[
            { label: 'Hearings', value: hearings.length, icon: Gavel, color: 'text-blue-600' },
            { label: 'Documents', value: docs.length, icon: FileText, color: 'text-purple-600' },
            { label: 'Bundle Approved', value: hasBundleDoc ? 'Yes' : 'No', icon: Package, color: hasBundleDoc ? 'text-emerald-600' : 'text-slate-400' },
            { label: 'Judge', value: caseData.judge ?? 'TBC', icon: Gavel, color: 'text-amber-600' },
            { label: 'Type', value: caseData.caseType, icon: Scale, color: 'text-slate-600' },
          ].map(({ label, value, icon: Icon, color }) => (
            <div key={label} className="bg-white dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-800 px-3 py-3 flex items-center gap-2">
              <Icon className={`w-4 h-4 shrink-0 ${color}`} />
              <div className="min-w-0">
                <p className="text-[10px] text-slate-400 truncate">{label}</p>
                <p className="text-sm font-semibold text-slate-900 dark:text-slate-100 truncate">{value}</p>
              </div>
            </div>
          ))}
        </div>

        {/* ── Tabs ── */}
        <div className="flex gap-1 flex-wrap">
          {TABS.map(({ id, label, icon: Icon }) => (
            <button
              key={id}
              onClick={() => setTab(id)}
              className={[
                'flex items-center gap-1.5 px-3 py-1.5 text-xs font-medium rounded-lg transition-colors',
                tab === id
                  ? 'bg-blue-600 text-white'
                  : 'bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800',
              ].join(' ')}
            >
              <Icon className="w-3.5 h-3.5" />
              {label}
            </button>
          ))}
        </div>

        {/* ── Tab content ── */}
        {tab === 'overview' && <OverviewTab caseData={caseData} />}
        {tab === 'hearings' && <HearingsTab caseId={caseId} />}
        {tab === 'documents' && <DocumentsTab caseId={caseId} />}
        {tab === 'allocations' && <AllocationsTab caseId={caseId} />}
        {tab === 'audit' && <AuditTab caseId={caseId} />}
      </div>
    </ClerkOSLayout>
  );
}

import ClerkOSLayout from '@/components/layout/ClerkOSLayout';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
} from '@/components/ui/dialog';
import { trpc } from '@/lib/trpc';
import { Search, AlertCircle, Plus, ChevronRight, ArrowRight, ExternalLink } from 'lucide-react';
import { useState } from 'react';
import { Link } from 'wouter';
import { toast } from 'sonner';

const STATUSES = ['all', 'open', 'in_progress', 'closed', 'on_hold'] as const;
type StatusFilter = (typeof STATUSES)[number];

const TRANSITIONS: Record<string, string[]> = {
  open: ['in_progress', 'on_hold', 'closed'],
  in_progress: ['on_hold', 'closed'],
  on_hold: ['in_progress', 'closed'],
  closed: [],
};

const STATUS_BADGE: Record<string, string> = {
  open: 'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-400',
  in_progress: 'bg-amber-100 text-amber-700 dark:bg-amber-900/30 dark:text-amber-400',
  closed: 'bg-slate-100 text-slate-600 dark:bg-slate-800 dark:text-slate-400',
  on_hold: 'bg-orange-100 text-orange-700 dark:bg-orange-900/30 dark:text-orange-400',
};

const TRANSITION_COLOUR: Record<string, string> = {
  in_progress: 'bg-amber-50 dark:bg-amber-900/20 text-amber-700 dark:text-amber-400 hover:bg-amber-100 dark:hover:bg-amber-900/40',
  on_hold: 'bg-orange-50 dark:bg-orange-900/20 text-orange-700 dark:text-orange-400 hover:bg-orange-100',
  closed: 'bg-slate-100 dark:bg-slate-800 text-slate-700 dark:text-slate-300 hover:bg-slate-200 dark:hover:bg-slate-700',
};

type Case = {
  id: number;
  referenceNumber: string;
  title: string;
  caseType: string;
  plaintiff: string;
  defendant: string;
  judge?: string | null;
  status: string;
  description?: string | null;
  createdAt: Date;
  updatedAt: Date;
};

function NewCaseDialog({ open, onOpenChange }: { open: boolean; onOpenChange: (v: boolean) => void }) {
  const utils = trpc.useContext();
  const create = trpc.cases.create.useMutation({
    onSuccess: () => {
      utils.cases.list.invalidate();
      utils.dashboard.stats.invalidate();
      onOpenChange(false);
      toast.success('Case created');
    },
    onError: (e) => toast.error(e.message),
  });

  const [form, setForm] = useState({
    referenceNumber: '',
    title: '',
    caseType: 'civil',
    plaintiff: '',
    defendant: '',
    judge: '',
    description: '',
  });

  const field = (key: keyof typeof form) => ({
    value: form[key],
    onChange: (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) =>
      setForm((f) => ({ ...f, [key]: e.target.value })),
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    create.mutate({
      referenceNumber: form.referenceNumber,
      title: form.title,
      caseType: form.caseType,
      plaintiff: form.plaintiff,
      defendant: form.defendant,
      judge: form.judge || undefined,
      description: form.description || undefined,
    });
  };

  const inputClass =
    'w-full px-3 py-2 text-sm border border-slate-200 dark:border-slate-700 rounded-lg bg-white dark:bg-slate-800 text-slate-900 dark:text-slate-100 placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-blue-500';

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-2xl">
        <DialogHeader>
          <DialogTitle>New Case</DialogTitle>
          <DialogDescription>Register a new matter in the court record.</DialogDescription>
        </DialogHeader>
        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-xs font-medium text-slate-500 dark:text-slate-400 mb-1">
                Reference Number *
              </label>
              <input {...field('referenceNumber')} required placeholder="2024-CIV-001" className={inputClass} />
            </div>
            <div>
              <label className="block text-xs font-medium text-slate-500 dark:text-slate-400 mb-1">
                Case Type *
              </label>
              <select {...field('caseType')} className={inputClass}>
                {['civil', 'criminal', 'family', 'commercial', 'administrative'].map((t) => (
                  <option key={t} value={t}>{t.charAt(0).toUpperCase() + t.slice(1)}</option>
                ))}
              </select>
            </div>
          </div>
          <div>
            <label className="block text-xs font-medium text-slate-500 dark:text-slate-400 mb-1">
              Case Title *
            </label>
            <input {...field('title')} required placeholder="Smith v. Jones" className={inputClass} />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-xs font-medium text-slate-500 dark:text-slate-400 mb-1">
                Plaintiff *
              </label>
              <input {...field('plaintiff')} required placeholder="Full name" className={inputClass} />
            </div>
            <div>
              <label className="block text-xs font-medium text-slate-500 dark:text-slate-400 mb-1">
                Defendant *
              </label>
              <input {...field('defendant')} required placeholder="Full name" className={inputClass} />
            </div>
          </div>
          <div>
            <label className="block text-xs font-medium text-slate-500 dark:text-slate-400 mb-1">
              Presiding Judge
            </label>
            <input {...field('judge')} placeholder="Judge name" className={inputClass} />
          </div>
          <div>
            <label className="block text-xs font-medium text-slate-500 dark:text-slate-400 mb-1">
              Notes
            </label>
            <textarea {...field('description')} rows={2} placeholder="Optional description" className={inputClass} />
          </div>
          <div className="flex justify-end gap-3 pt-2">
            <button
              type="button"
              onClick={() => onOpenChange(false)}
              className="px-4 py-2 text-sm rounded-lg border border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800"
            >
              Cancel
            </button>
            <button
              type="submit"
              disabled={create.isLoading}
              className="px-4 py-2 text-sm font-medium rounded-lg bg-blue-600 text-white hover:bg-blue-700 disabled:opacity-50 transition-colors"
            >
              {create.isLoading ? 'Creating…' : 'Create Case'}
            </button>
          </div>
        </form>
      </DialogContent>
    </Dialog>
  );
}

function CaseDetailPanel({
  caseItem,
  onClose,
}: {
  caseItem: Case;
  onClose: () => void;
}) {
  const utils = trpc.useContext();
  const transition = trpc.cases.transition.useMutation({
    onSuccess: () => {
      utils.cases.list.invalidate();
      utils.dashboard.stats.invalidate();
      toast.success('Case status updated');
      onClose();
    },
    onError: (e) => toast.error(e.message),
  });

  const nextStates = TRANSITIONS[caseItem.status] ?? [];

  return (
    <div className="fixed inset-0 z-40 flex">
      <div className="flex-1 bg-black/30" onClick={onClose} />
      <aside className="w-full max-w-md bg-white dark:bg-slate-900 border-l border-slate-200 dark:border-slate-800 h-full overflow-y-auto shadow-2xl flex flex-col">
        <div className="px-6 py-5 border-b border-slate-200 dark:border-slate-800 flex items-start justify-between gap-4">
          <div className="min-w-0">
            <p className="text-xs font-mono text-slate-400 dark:text-slate-500">{caseItem.referenceNumber}</p>
            <h2 className="text-base font-bold text-slate-900 dark:text-slate-100 mt-0.5">{caseItem.title}</h2>
          </div>
          <button
            onClick={onClose}
            className="p-1.5 rounded-md text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors flex-shrink-0"
          >
            ✕
          </button>
        </div>

        <div className="flex-1 px-6 py-5 space-y-5">
          {/* Status + type */}
          <div className="flex items-center gap-3">
            <span
              className={`text-xs font-medium px-2.5 py-1 rounded-full ${STATUS_BADGE[caseItem.status] ?? ''}`}
            >
              {caseItem.status.replace('_', ' ')}
            </span>
            <span className="text-xs text-slate-400 dark:text-slate-500 capitalize">{caseItem.caseType}</span>
          </div>

          {/* Parties */}
          <div className="grid grid-cols-2 gap-4">
            <div>
              <p className="text-[10px] font-medium text-slate-400 dark:text-slate-500 uppercase tracking-wide mb-1">
                Plaintiff
              </p>
              <p className="text-sm font-medium text-slate-900 dark:text-slate-100">{caseItem.plaintiff}</p>
            </div>
            <div>
              <p className="text-[10px] font-medium text-slate-400 dark:text-slate-500 uppercase tracking-wide mb-1">
                Defendant
              </p>
              <p className="text-sm font-medium text-slate-900 dark:text-slate-100">{caseItem.defendant}</p>
            </div>
          </div>

          {caseItem.judge && (
            <div>
              <p className="text-[10px] font-medium text-slate-400 dark:text-slate-500 uppercase tracking-wide mb-1">
                Judge
              </p>
              <p className="text-sm text-slate-700 dark:text-slate-300">{caseItem.judge}</p>
            </div>
          )}

          {caseItem.description && (
            <div>
              <p className="text-[10px] font-medium text-slate-400 dark:text-slate-500 uppercase tracking-wide mb-1">
                Description
              </p>
              <p className="text-sm text-slate-600 dark:text-slate-400">{caseItem.description}</p>
            </div>
          )}

          <div className="text-xs text-slate-400 dark:text-slate-500">
            Created {new Date(caseItem.createdAt).toLocaleDateString('en-GB', { day: 'numeric', month: 'short', year: 'numeric' })}
          </div>

          {/* State machine transitions */}
          {nextStates.length > 0 && (
            <div>
              <p className="text-[10px] font-medium text-slate-400 dark:text-slate-500 uppercase tracking-wide mb-2">
                Transition Status
              </p>
              <div className="flex flex-wrap gap-2">
                {nextStates.map((next) => (
                  <button
                    key={next}
                    onClick={() => transition.mutate({ id: caseItem.id, status: next as 'open' | 'in_progress' | 'on_hold' | 'closed' })}
                    disabled={transition.isLoading}
                    className={`flex items-center gap-1.5 px-3 py-1.5 text-xs font-medium rounded-lg transition-colors disabled:opacity-50 ${TRANSITION_COLOUR[next] ?? ''}`}
                  >
                    <ArrowRight className="w-3 h-3" />
                    {next.replace('_', ' ')}
                  </button>
                ))}
              </div>
            </div>
          )}
        </div>
      </aside>
    </div>
  );
}

export default function Cases() {
  const [search, setSearch] = useState('');
  const [status, setStatus] = useState<StatusFilter>('all');
  const [showNew, setShowNew] = useState(false);
  const [selected, setSelected] = useState<Case | null>(null);

  const listQuery = trpc.cases.list.useQuery(
    status === 'all' ? undefined : { status },
    { retry: false },
  );

  const searchQuery = trpc.cases.search.useQuery(
    { query: search },
    { enabled: search.trim().length > 1, retry: false },
  );

  const cases = search.trim().length > 1
    ? (searchQuery.data ?? [])
    : (listQuery.data ?? []);

  const isLoading = search.trim().length > 1 ? searchQuery.isLoading : listQuery.isLoading;
  const hasError = listQuery.error || searchQuery.error;

  return (
    <ClerkOSLayout>
      <div className="p-6 max-w-7xl mx-auto">
        <div className="mb-6 flex items-start justify-between gap-4">
          <div>
            <h1 className="text-2xl font-bold text-slate-900 dark:text-slate-100">Cases</h1>
            <p className="text-sm text-slate-500 dark:text-slate-400 mt-1">
              Matter index — all active and archived cases
            </p>
          </div>
          <button
            onClick={() => setShowNew(true)}
            className="flex items-center gap-2 px-4 py-2 text-sm font-medium rounded-lg bg-blue-600 text-white hover:bg-blue-700 transition-colors flex-shrink-0"
          >
            <Plus className="w-4 h-4" />
            New Case
          </button>
        </div>

        {hasError && (
          <div className="mb-4 flex items-center gap-3 p-4 bg-amber-50 dark:bg-amber-900/20 border border-amber-200 dark:border-amber-800 rounded-xl">
            <AlertCircle className="w-5 h-5 text-amber-600 flex-shrink-0" />
            <p className="text-sm text-amber-700 dark:text-amber-300">
              Database not connected — no cases to display.
            </p>
          </div>
        )}

        {/* Controls */}
        <div className="flex flex-col sm:flex-row gap-3 mb-5">
          <div className="relative flex-1 max-w-sm">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400" />
            <input
              type="text"
              placeholder="Search cases…"
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="w-full pl-9 pr-4 py-2 text-sm border border-slate-200 dark:border-slate-700 rounded-lg bg-white dark:bg-slate-900 text-slate-900 dark:text-slate-100 placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
          </div>
          <div className="flex gap-1 flex-wrap">
            {STATUSES.map((s) => (
              <button
                key={s}
                onClick={() => setStatus(s)}
                className={[
                  'px-3 py-1.5 text-xs font-medium rounded-lg transition-colors',
                  status === s
                    ? 'bg-blue-600 text-white'
                    : 'bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800',
                ].join(' ')}
              >
                {s.replace('_', ' ')}
              </button>
            ))}
          </div>
        </div>

        {/* Table */}
        <div className="bg-white dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-800 overflow-hidden">
          <table className="w-full text-sm">
            <thead>
              <tr className="border-b border-slate-200 dark:border-slate-800">
                {['Reference', 'Title', 'Type', 'Plaintiff', 'Defendant', 'Judge', 'Status', ''].map((h) => (
                  <th
                    key={h}
                    className="px-4 py-3 text-left text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wide"
                  >
                    {h}
                  </th>
                ))}
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
              {isLoading ? (
                Array.from({ length: 5 }).map((_, i) => (
                  <tr key={i}>
                    {Array.from({ length: 8 }).map((_, j) => (
                      <td key={j} className="px-4 py-3">
                        <div className="h-3.5 bg-slate-200 dark:bg-slate-800 rounded animate-pulse" />
                      </td>
                    ))}
                  </tr>
                ))
              ) : cases.length === 0 ? (
                <tr>
                  <td colSpan={8} className="px-4 py-12 text-center text-slate-400 text-sm">
                    {search ? 'No cases match your search' : 'No cases found — create one to get started'}
                  </td>
                </tr>
              ) : (
                cases.map((c) => (
                  <tr
                    key={c.id}
                    className="hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors cursor-pointer"
                    onClick={() => setSelected(c as Case)}
                  >
                    <td className="px-4 py-3 font-mono text-xs text-slate-500 dark:text-slate-400">
                      {c.referenceNumber}
                    </td>
                    <td className="px-4 py-3 font-medium text-slate-900 dark:text-slate-100 max-w-[180px] truncate">
                      {c.title}
                    </td>
                    <td className="px-4 py-3 text-slate-500 dark:text-slate-400 capitalize">{c.caseType}</td>
                    <td className="px-4 py-3 text-slate-700 dark:text-slate-300 truncate max-w-[130px]">
                      {c.plaintiff}
                    </td>
                    <td className="px-4 py-3 text-slate-700 dark:text-slate-300 truncate max-w-[130px]">
                      {c.defendant}
                    </td>
                    <td className="px-4 py-3 text-slate-500 dark:text-slate-400 truncate max-w-[110px]">
                      {c.judge ?? '—'}
                    </td>
                    <td className="px-4 py-3">
                      <span
                        className={`text-[10px] font-medium px-2 py-0.5 rounded-full ${STATUS_BADGE[c.status] ?? ''}`}
                      >
                        {c.status.replace('_', ' ')}
                      </span>
                    </td>
                    <td className="px-4 py-3">
                      <div className="flex items-center gap-2">
                        <ChevronRight className="w-4 h-4 text-slate-400" />
                        <Link href={`/cases/${c.id}`} onClick={(e) => e.stopPropagation()}>
                          <span className="text-[10px] text-blue-600 dark:text-blue-400 hover:underline flex items-center gap-0.5">
                            <ExternalLink className="w-3 h-3" /> Detail
                          </span>
                        </Link>
                      </div>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>

        {cases.length > 0 && (
          <p className="mt-3 text-xs text-slate-400 dark:text-slate-500">
            {cases.length} case{cases.length !== 1 ? 's' : ''} shown
          </p>
        )}
      </div>

      <NewCaseDialog open={showNew} onOpenChange={setShowNew} />
      {selected && <CaseDetailPanel caseItem={selected} onClose={() => setSelected(null)} />}
    </ClerkOSLayout>
  );
}

import { useState, useEffect, FormEvent } from 'react';
import { useLocation, useSearch } from 'wouter';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { Loader2, CheckCircle, AlertCircle, ArrowLeft, FileText, ShieldCheck } from 'lucide-react';
import { toast } from 'sonner';

interface CompanyData {
  number: string;
  name: string;
  status: string;
  type?: string;
  incorporationDate?: string;
}

interface FilingDeadline {
  nextDue: string;
  daysUntilDue: number;
  overdue: boolean;
}

interface OverdueFiling {
  type: string;
  description: string;
  dueDate: string;
  daysOverdue: number;
  penaltyRisk: number;
}

interface Penalty {
  estimated: number;
  description: string;
}

interface ComplianceData {
  status: 'compliant' | 'warning' | 'overdue';
  riskLevel: 'none' | 'low' | 'medium' | 'high';
  accounts: FilingDeadline;
  confirmationStatement?: FilingDeadline;
  overdueFilings: OverdueFiling[];
  penalties?: Penalty[]; // Optional - only present if there are overdue filings
}

export default function ComplianceBundle() {
  const [, setLocation] = useLocation();
  const search = useSearch();
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(false);
  const [bundleId, setBundleId] = useState('');
  const [companyData, setCompanyData] = useState<CompanyData | null>(null);
  const [complianceData, setComplianceData] = useState<ComplianceData | null>(null);
  const [error, setError] = useState('');
  const [monitored, setMonitored] = useState(false);
  const [checkoutLoading, setCheckoutLoading] = useState(false);

  const [formData, setFormData] = useState({
    companyName: '',
    companyNumber: '',
    requestorName: '',
    requestorEmail: '',
    bundleType: 'full',
  });

  // Check protection status whenever we have a company number (including on Stripe return)
  useEffect(() => {
    if (!companyData?.number) return;

    fetch(`/api/protection-status?companyNumber=${encodeURIComponent(companyData.number)}`)
      .then((r) => r.json())
      .then((data) => {
        if (data.monitored) {
          setMonitored(true);
        }
      })
      .catch(() => {/* non-blocking */});
  }, [companyData?.number]);

  // Handle return from Stripe (?activated=1&company=...)
  useEffect(() => {
    const params = new URLSearchParams(search);
    if (params.get('activated') === '1') {
      const companyNumber = params.get('company');
      if (companyNumber) {
        fetch(`/api/protection-status?companyNumber=${encodeURIComponent(companyNumber)}`)
          .then((r) => r.json())
          .then((data) => {
            if (data.monitored) {
              setMonitored(true);
              toast.success('Protection activated — your company is now being monitored.');
            }
          })
          .catch(() => {/* non-blocking */});
      }
    }
  }, [search]);

  const handleActivate = async () => {
    if (!companyData) return;
    setCheckoutLoading(true);
    try {
      const response = await fetch('/api/stripe/checkout', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          companyNumber: companyData.number,
          companyName: companyData.name,
        }),
      });
      const data = await response.json();
      if (response.ok && data.url) {
        window.location.href = data.url;
      } else {
        toast.error(data.error || 'Could not start checkout. Please try again.');
      }
    } catch {
      toast.error('Network error. Please check your connection.');
    } finally {
      setCheckoutLoading(false);
    }
  };

  const handleSubmit = async (e: FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    try {
      const response = await fetch('/api/compliance-bundle', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(formData),
      });

      const data = await response.json();

      if (response.ok && data.ok) {
        setSuccess(true);
        setBundleId(data.bundleId);
        setCompanyData(data.company);
        setComplianceData(data.compliance);
        toast.success(data.message || 'Compliance data retrieved successfully!');

        // Reset form
        setFormData({
          companyName: '',
          companyNumber: '',
          requestorName: '',
          requestorEmail: '',
          bundleType: 'full',
        });
      } else {
        setError(data.error || 'Failed to submit form. Please try again.');
        toast.error(data.error || 'Submission failed');
      }
    } catch (err) {
      console.error('Error submitting form:', err);
      setError('Network error. Please check your connection and try again.');
      toast.error('Network error occurred');
    } finally {
      setLoading(false);
    }
  };

  const getRiskColor = (riskLevel: string) => {
    switch (riskLevel) {
      case 'high': return 'bg-red-100 border-red-300 text-red-800';
      case 'medium': return 'bg-orange-100 border-orange-300 text-orange-800';
      case 'low': return 'bg-yellow-100 border-yellow-300 text-yellow-800';
      default: return 'bg-green-100 border-green-300 text-green-800';
    }
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'overdue': return 'bg-red-100 border-red-300 text-red-800';
      case 'warning': return 'bg-orange-100 border-orange-300 text-orange-800';
      default: return 'bg-green-100 border-green-300 text-green-800';
    }
  };

  /**
   * Safely format date, handling 'N/A' and invalid dates
   */
  const formatDate = (dateString: string): string => {
    if (!dateString || dateString === 'N/A') {
      return 'Not available';
    }

    try {
      const date = new Date(dateString);
      if (isNaN(date.getTime())) {
        return 'Not available';
      }
      return date.toLocaleDateString('en-GB');
    } catch {
      return 'Not available';
    }
  };

  /**
   * Check if deadline data is available
   */
  const isDeadlineAvailable = (daysUntilDue: number, dueDate: string): boolean => {
    return daysUntilDue !== 999 && dueDate !== 'N/A';
  };

  if (success && companyData && complianceData) {
    return (
      <div className="min-h-screen bg-[#F8F8F8] py-8 px-4">
        <div className="max-w-4xl mx-auto space-y-6">
          {/* Header */}
          <Card className="bg-white border-[#1A1A1A]/10">
            <CardHeader>
              <div className="flex items-start justify-between">
                <div>
                  <CardTitle className="text-2xl text-[#1A1A1A] mb-2">{companyData.name}</CardTitle>
                  <CardDescription className="text-gray-600">
                    Company No: {companyData.number} • Status: {companyData.status}
                  </CardDescription>
                  <p className="text-sm text-gray-500 mt-1">Bundle Reference: <span className="font-mono text-[#C9A64A]">{bundleId}</span></p>
                </div>
                <div className={`px-4 py-2 rounded-lg border ${getRiskColor(complianceData.riskLevel)}`}>
                  <p className="text-sm font-semibold uppercase">{complianceData.riskLevel} Risk</p>
                </div>
              </div>
            </CardHeader>
          </Card>

          {/* Compliance Status */}
          <Card className="bg-white border-[#1A1A1A]/10">
            <CardHeader>
              <CardTitle className="text-xl text-[#1A1A1A]">Compliance Status</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className={`p-4 rounded-lg border ${getStatusColor(complianceData.status)}`}>
                <p className="font-semibold text-lg mb-1 capitalize">{complianceData.status}</p>
                <p className="text-sm">
                  {complianceData.status === 'compliant' && 'All filings are up to date'}
                  {complianceData.status === 'warning' && 'Upcoming deadlines - action required soon'}
                  {complianceData.status === 'overdue' && 'Immediate action required - filings overdue'}
                </p>
              </div>

              {/* Filing Deadlines */}
              <div className="grid md:grid-cols-2 gap-4">
                {/* Accounts */}
                {isDeadlineAvailable(complianceData.accounts.daysUntilDue, complianceData.accounts.nextDue) ? (
                  <div className={`p-4 rounded-lg border ${complianceData.accounts.overdue ? 'bg-red-50 border-red-200' : 'bg-blue-50 border-blue-200'}`}>
                    <p className="font-semibold text-sm mb-2 flex items-center gap-2">
                      <FileText className="w-4 h-4" />
                      Annual Accounts
                    </p>
                    <p className={`text-lg font-semibold ${complianceData.accounts.overdue ? 'text-red-700' : 'text-blue-700'}`}>
                      {complianceData.accounts.overdue ? `${Math.abs(complianceData.accounts.daysUntilDue)} days overdue` : `Due in ${complianceData.accounts.daysUntilDue} days`}
                    </p>
                    <p className="text-sm text-gray-600 mt-1">Due: {formatDate(complianceData.accounts.nextDue)}</p>
                  </div>
                ) : (
                  <div className="p-4 rounded-lg border bg-gray-50 border-gray-200">
                    <p className="font-semibold text-sm mb-2 flex items-center gap-2">
                      <FileText className="w-4 h-4" />
                      Annual Accounts
                    </p>
                    <p className="text-sm text-gray-600">No accounts data available from Companies House</p>
                  </div>
                )}

                {/* Confirmation Statement */}
                {complianceData.confirmationStatement && isDeadlineAvailable(complianceData.confirmationStatement.daysUntilDue, complianceData.confirmationStatement.nextDue) ? (
                  <div className={`p-4 rounded-lg border ${complianceData.confirmationStatement.overdue ? 'bg-red-50 border-red-200' : 'bg-blue-50 border-blue-200'}`}>
                    <p className="font-semibold text-sm mb-2 flex items-center gap-2">
                      <FileText className="w-4 h-4" />
                      Confirmation Statement
                    </p>
                    <p className={`text-lg font-semibold ${complianceData.confirmationStatement.overdue ? 'text-red-700' : 'text-blue-700'}`}>
                      {complianceData.confirmationStatement.overdue ? `${Math.abs(complianceData.confirmationStatement.daysUntilDue)} days overdue` : `Due in ${complianceData.confirmationStatement.daysUntilDue} days`}
                    </p>
                    <p className="text-sm text-gray-600 mt-1">Due: {formatDate(complianceData.confirmationStatement.nextDue)}</p>
                  </div>
                ) : complianceData.confirmationStatement ? (
                  <div className="p-4 rounded-lg border bg-gray-50 border-gray-200">
                    <p className="font-semibold text-sm mb-2 flex items-center gap-2">
                      <FileText className="w-4 h-4" />
                      Confirmation Statement
                    </p>
                    <p className="text-sm text-gray-600">No confirmation statement data available</p>
                  </div>
                ) : null}
              </div>
            </CardContent>
          </Card>

          {/* Overdue Filings */}
          {complianceData.overdueFilings && complianceData.overdueFilings.length > 0 && (
            <Card className="bg-white border-red-300">
              <CardHeader>
                <CardTitle className="text-xl text-red-800 flex items-center gap-2">
                  <AlertCircle className="w-5 h-5" />
                  Overdue Filings
                </CardTitle>
                <CardDescription className="text-red-600">
                  Immediate action required to avoid additional penalties
                </CardDescription>
              </CardHeader>
              <CardContent className="space-y-3">
                {complianceData.overdueFilings.map((filing, idx) => (
                  <div key={idx} className="p-4 bg-red-50 border border-red-200 rounded-lg">
                    <div className="flex items-start justify-between mb-2">
                      <div>
                        <p className="font-semibold text-red-900">{filing.description}</p>
                        <p className="text-sm text-red-700">
                          Due: {formatDate(filing.dueDate)} ({filing.daysOverdue} days overdue)
                        </p>
                      </div>
                      <div className="text-right">
                        <p className="text-lg font-bold text-red-800">£{filing.penaltyRisk.toLocaleString()}</p>
                        <p className="text-xs text-red-600">penalty risk</p>
                      </div>
                    </div>
                  </div>
                ))}
              </CardContent>
            </Card>
          )}

          {/* Penalties */}
          {complianceData.penalties && complianceData.penalties.length > 0 && (
            <Card className="bg-white border-orange-300">
              <CardHeader>
                <CardTitle className="text-xl text-orange-800">Estimated Penalties</CardTitle>
                <CardDescription className="text-orange-600">
                  Current or potential late filing penalties
                </CardDescription>
              </CardHeader>
              <CardContent className="space-y-3">
                {complianceData.penalties.map((penalty, idx) => (
                  <div key={idx} className="p-4 bg-orange-50 border border-orange-200 rounded-lg flex items-center justify-between">
                    <p className="text-sm text-orange-900">{penalty.description}</p>
                    <p className="text-xl font-bold text-orange-800">£{penalty.estimated.toLocaleString()}</p>
                  </div>
                ))}
                <div className="p-3 bg-orange-100 border border-orange-300 rounded-lg">
                  <p className="text-sm font-semibold text-orange-900">
                    Total Estimated Penalties: £{complianceData.penalties.reduce((sum, p) => sum + p.estimated, 0).toLocaleString()}
                  </p>
                </div>
              </CardContent>
            </Card>
          )}

          {/* Protection status / CTA */}
          {monitored ? (
            <Card className="bg-green-50 border-green-300">
              <CardContent className="pt-6">
                <div className="flex items-start gap-4 mb-4">
                  <ShieldCheck className="w-8 h-8 text-green-600 flex-shrink-0 mt-0.5" />
                  <div>
                    <p className="text-sm font-semibold text-green-700 uppercase tracking-wide">Protection active</p>
                    <h2 className="text-xl font-bold text-green-900 mt-0.5">
                      {companyData.name} is being monitored
                    </h2>
                    <p className="text-sm text-green-700 mt-1">
                      You'll receive alerts before any compliance deadlines are missed.
                    </p>
                  </div>
                </div>
                <Button
                  onClick={() => {
                    setSuccess(false);
                    setCompanyData(null);
                    setComplianceData(null);
                    setMonitored(false);
                  }}
                  variant="outline"
                  className="border-green-400 text-green-800 hover:bg-green-100"
                >
                  Check Another Company
                </Button>
              </CardContent>
            </Card>
          ) : (
            <Card className="bg-white border-[#1A1A1A]/10">
              <CardContent className="pt-6 space-y-4">
                <div>
                  <h3 className="text-lg font-semibold text-[#1A1A1A]">Activate monitoring</h3>
                  <p className="text-sm text-gray-600 mt-1">
                    Get automatic alerts before filing deadlines for {companyData.name}. £3/month, cancel anytime.
                  </p>
                </div>
                <Button
                  onClick={handleActivate}
                  disabled={checkoutLoading}
                  className="w-full bg-[#C9A64A] hover:bg-[#B8954A] text-white disabled:opacity-50"
                >
                  {checkoutLoading ? (
                    <>
                      <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                      Redirecting to checkout…
                    </>
                  ) : (
                    <>
                      <ShieldCheck className="w-4 h-4 mr-2" />
                      Activate Protection — £3/mo
                    </>
                  )}
                </Button>
                <div className="flex gap-3">
                  <Button
                    onClick={() => {
                      setSuccess(false);
                      setCompanyData(null);
                      setComplianceData(null);
                    }}
                    variant="outline"
                    className="flex-1 border-[#1A1A1A]/20 hover:bg-gray-100"
                  >
                    Check Another Company
                  </Button>
                  <Button
                    onClick={() => setLocation('/fineguard')}
                    variant="outline"
                    className="flex-1 border-[#1A1A1A]/20 hover:bg-gray-100"
                  >
                    <ArrowLeft className="w-4 h-4 mr-2" />
                    Back to FineGuard
                  </Button>
                </div>
              </CardContent>
            </Card>
          )}
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#F8F8F8] py-12 px-4">
      <div className="max-w-2xl mx-auto">
        <div className="mb-8 text-center">
          <h1 className="text-4xl font-bold text-[#1A1A1A] mb-4">Compliance Bundle Request</h1>
          <p className="text-gray-600 text-lg">
            Get your comprehensive Companies House compliance report
          </p>
        </div>

        <Card className="bg-white border-[#1A1A1A]/10">
          <CardHeader>
            <CardTitle className="text-2xl text-[#1A1A1A]">Request Compliance Bundle</CardTitle>
            <CardDescription className="text-gray-600">
              Provide your company information to receive a detailed compliance bundle
            </CardDescription>
          </CardHeader>
          <CardContent>
            <form onSubmit={handleSubmit} className="space-y-6">
              {error && (
                <Alert variant="destructive" className="bg-red-50 border-red-200">
                  <AlertCircle className="h-4 w-4" />
                  <AlertDescription>{error}</AlertDescription>
                </Alert>
              )}

              {/* Company Information */}
              <div className="space-y-4">
                <h3 className="text-lg font-semibold text-[#1A1A1A] border-b border-gray-200 pb-2">
                  Company Information
                </h3>

                <div className="space-y-2">
                  <Label htmlFor="companyName" className="text-gray-700">
                    Company Name <span className="text-red-500">*</span>
                  </Label>
                  <Input
                    id="companyName"
                    required
                    value={formData.companyName}
                    onChange={(e) => setFormData({ ...formData, companyName: e.target.value })}
                    className="border-gray-300 focus:border-[#C9A64A] focus:ring-[#C9A64A]"
                    placeholder="Your Company Ltd"
                  />
                </div>

                <div className="space-y-2">
                  <Label htmlFor="companyNumber" className="text-gray-700">
                    Companies House Number <span className="text-red-500">*</span>
                  </Label>
                  <Input
                    id="companyNumber"
                    required
                    value={formData.companyNumber}
                    onChange={(e) => setFormData({ ...formData, companyNumber: e.target.value })}
                    className="border-gray-300 focus:border-[#C9A64A] focus:ring-[#C9A64A]"
                    placeholder="12345678"
                    maxLength={8}
                  />
                  <p className="text-sm text-gray-500">
                    8-digit company registration number
                  </p>
                </div>
              </div>

              {/* Contact Information */}
              <div className="space-y-4">
                <h3 className="text-lg font-semibold text-[#1A1A1A] border-b border-gray-200 pb-2">
                  Contact Information
                </h3>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <Label htmlFor="requestorName" className="text-gray-700">
                      Your Name
                    </Label>
                    <Input
                      id="requestorName"
                      value={formData.requestorName}
                      onChange={(e) => setFormData({ ...formData, requestorName: e.target.value })}
                      className="border-gray-300 focus:border-[#C9A64A] focus:ring-[#C9A64A]"
                      placeholder="John Doe"
                    />
                  </div>

                  <div className="space-y-2">
                    <Label htmlFor="requestorEmail" className="text-gray-700">
                      Email Address
                    </Label>
                    <Input
                      id="requestorEmail"
                      type="email"
                      value={formData.requestorEmail}
                      onChange={(e) => setFormData({ ...formData, requestorEmail: e.target.value })}
                      className="border-gray-300 focus:border-[#C9A64A] focus:ring-[#C9A64A]"
                      placeholder="john@company.co.uk"
                    />
                  </div>
                </div>
              </div>

              {/* Bundle Type */}
              <div className="space-y-2">
                <Label htmlFor="bundleType" className="text-gray-700">
                  Bundle Type
                </Label>
                <Select
                  value={formData.bundleType}
                  onValueChange={(value) => setFormData({ ...formData, bundleType: value })}
                >
                  <SelectTrigger className="border-gray-300 focus:border-[#C9A64A] focus:ring-[#C9A64A]">
                    <SelectValue placeholder="Select bundle type" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="full">
                      <div className="flex flex-col items-start">
                        <span className="font-semibold">Full Compliance Bundle</span>
                        <span className="text-sm text-gray-500">Complete report with all filings</span>
                      </div>
                    </SelectItem>
                    <SelectItem value="basic">
                      <div className="flex flex-col items-start">
                        <span className="font-semibold">Basic Report</span>
                        <span className="text-sm text-gray-500">Essential compliance information only</span>
                      </div>
                    </SelectItem>
                    <SelectItem value="custom">
                      <div className="flex flex-col items-start">
                        <span className="font-semibold">Custom Bundle</span>
                        <span className="text-sm text-gray-500">We'll contact you for requirements</span>
                      </div>
                    </SelectItem>
                  </SelectContent>
                </Select>
              </div>

              <div className="bg-blue-50 border border-blue-200 rounded-lg p-4">
                <div className="flex gap-3">
                  <FileText className="w-5 h-5 text-blue-600 flex-shrink-0 mt-0.5" />
                  <div className="text-sm text-blue-800">
                    <p className="font-semibold mb-1">What You'll Receive:</p>
                    <ul className="space-y-1">
                      <li>• Current filing status from Companies House</li>
                      <li>• List of overdue or upcoming deadlines</li>
                      <li>• Automated compliance calendar</li>
                      <li>• Mobile alerts for important dates</li>
                    </ul>
                  </div>
                </div>
              </div>

              <div className="flex gap-3">
                <Button
                  type="button"
                  variant="outline"
                  onClick={() => setLocation('/fineguard')}
                  className="flex-1 border-gray-300 hover:bg-gray-100"
                >
                  Cancel
                </Button>
                <Button
                  type="submit"
                  disabled={loading}
                  className="flex-1 bg-[#C9A64A] hover:bg-[#B8954A] text-white disabled:opacity-50"
                >
                  {loading ? (
                    <>
                      <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                      Submitting...
                    </>
                  ) : (
                    'Request Bundle'
                  )}
                </Button>
              </div>
            </form>
          </CardContent>
        </Card>

        <p className="text-center text-gray-500 text-sm mt-6">
          Your information is secure and will only be used to generate your compliance bundle
        </p>
      </div>
    </div>
  );
}

import ClerkOSLayout from '@/components/layout/ClerkOSLayout';
import { trpc } from '@/lib/trpc';
import { Scale, Gavel, ListTodo, TrendingUp, AlertCircle, XCircle, CalendarCheck, ArrowRight } from 'lucide-react';
import { Link } from 'wouter';

function Skeleton({ className = '' }: { className?: string }) {
  return (
    <div className={`animate-pulse bg-slate-200 dark:bg-slate-800 rounded ${className}`} />
  );
}

function StatCard({
  label,
  value,
  icon: Icon,
  accent = 'blue',
  loading = false,
}: {
  label: string;
  value: number | string;
  icon: React.FC<{ className?: string }>;
  accent?: 'blue' | 'emerald' | 'amber' | 'violet' | 'slate' | 'rose';
  loading?: boolean;
}) {
  const colours: Record<string, string> = {
    blue: 'bg-blue-50 dark:bg-blue-900/20 text-blue-600 dark:text-blue-400',
    emerald: 'bg-emerald-50 dark:bg-emerald-900/20 text-emerald-600 dark:text-emerald-400',
    amber: 'bg-amber-50 dark:bg-amber-900/20 text-amber-600 dark:text-amber-400',
    violet: 'bg-violet-50 dark:bg-violet-900/20 text-violet-600 dark:text-violet-400',
    slate: 'bg-slate-100 dark:bg-slate-800 text-slate-500 dark:text-slate-400',
    rose: 'bg-rose-50 dark:bg-rose-900/20 text-rose-600 dark:text-rose-400',
  };

  return (
    <div className="bg-white dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-800 p-5">
      <div className="flex items-start justify-between">
        <div className="flex-1">
          <p className="text-xs font-medium text-slate-500 dark:text-slate-400 uppercase tracking-wide">
            {label}
          </p>
          {loading ? (
            <Skeleton className="h-8 w-16 mt-2" />
          ) : (
            <p className="text-3xl font-bold text-slate-900 dark:text-slate-100 mt-1">{value}</p>
          )}
        </div>
        <div className={`w-10 h-10 rounded-lg flex items-center justify-center ${colours[accent]}`}>
          <Icon className="w-5 h-5" />
        </div>
      </div>
    </div>
  );
}

const STATUS_BADGE: Record<string, string> = {
  open: 'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-400',
  in_progress: 'bg-amber-100 text-amber-700 dark:bg-amber-900/30 dark:text-amber-400',
  closed: 'bg-slate-100 text-slate-600 dark:bg-slate-800 dark:text-slate-400',
