        <DialogHeader>
          <DialogTitle>Add Diary Entry</DialogTitle>
          <DialogDescription>
            {new Date(date + 'T00:00:00').toLocaleDateString('en-GB', {
              weekday: 'long',
              day: 'numeric',
              month: 'long',
              year: 'numeric',
            })}
