// conic-gradient stop from cumulative percentages
function buildConic(segments: { pct: number; color: string }[]) {
  let cursor = 0;
  return segments
    .map(({ pct, color }) => {
      const start = cursor;
      cursor += pct;
      return `${color} ${start}% ${cursor}%`;
    })
    .join(', ');
}

