          {/* User avatar */}
          <div className="flex h-8 w-8 items-center justify-center rounded-full bg-[#7C3AED] text-xs font-bold">
            AC
          </div>
        </div>
      </header>

      <main className="mx-auto max-w-7xl space-y-6 px-6 py-8">
        {/* ── Page title ── */}
